/*
This special class is used for custom controls. It renders a square with optionally a label. 
*/
df.WebDesignerControl = class WebDesignerControl extends df.WebBaseControl{

constructor(sName, tDef){
    super(sName, tDef);

    this.pbShowLabel = false;
    this._sControlClass = "WebDesignerControl";
}

openHtml(aHtml){
    super.openHtml(aHtml);
    
    aHtml.push('<div class="WebDC_PlaceHolder">');
}

closeHtml(aHtml){
    aHtml.push('</div>');

    super.closeHtml(aHtml);
}

afterRender(){
    this._eControl = df.dom.query(this._eElem, "div.WebDC_PlaceHolder");

    super.afterRender();
}

}

