df.WebBaseUIObject.prototype._uiAfterRender = df.WebBaseUIObject.prototype.afterRender;

df.WebBaseUIObject.prototype.afterRender = function(){
    this._uiAfterRender();
    
    df.events.addDomListener("click", this._eElem, this.prevOnClick, this);
    df.events.addDomListener("dblclick", this._eElem, this.prevOnDblClick, this);
};

df.WebBaseUIObject.prototype.prevOnClick = function(oEvent){
    // if(!oEvent.e._bPreviewerSelected){
        // oPreviewer.studioSelectObject(this);
    // }
    
    // oEvent.e._bPreviewerSelected = true;
    
    oPreviewer.studioSelectObject(this);
    oEvent.stop();
};
df.WebBaseUIObject.prototype.prevOnDblClick = function(oEvent){
    // if(!oEvent.e._bPreviewerSelected){
        // oPreviewer.studioSelectObject(this);
    // }
    
    // oEvent.e._bPreviewerSelected = true;
    
    oPreviewer.studioGotoObject(this);
    oEvent.stop();
};
df.WebBaseUIObject.prototype.getPreviewerElem = function(){
    //  We need to do it like this as we cannot add / alter functions on mixins...
    if(this._bIsColumn){
        if(this._oParent.pbShowHeader){
            return this._oParent.getColHead(this);
        }
        return this._oParent.getCell(0, this._iCol);
    }

    return this._eElem;
};

df.WebBaseUIObject.prototype.getInsertionObject = function(){
    return this.getPreviewerElem();
};

df.WebBaseUIObject.prototype.highlight = function(){
    var oObj = this;
    
    //  Special support for tabdialog
    while(oObj._oParent){
        oObj = oObj._oParent;
        if(oObj instanceof df.WebCard){
            oObj.show();
        }
    }
};

df.WebBaseUIObject.prototype.isActive = function(){
    return true;    //  Enable switching to disabled tabs and expanding disabled menu's
};



