df.WebAccordionCard.prototype.onBtnClick = df.WebCard.prototype.onBtnClick = function(oEvent){
    oPreviewer.studioSelectObject(this);
    oEvent.stop();
};

df.WebAccordionContainer.prototype._showCard = df.WebAccordionContainer.prototype.showCard;
df.WebAccordionContainer.prototype.showCard = function(oDisplay, bOptFirst){
    var aOpened = [];
    
    df.WebAccordionContainer.prototype._showCard.apply(this, arguments);
    
    if(this.pbMultiOpen && !bOptFirst){
        for(i = 0; i < this._aCards.length; i++){
            if(this._aCards[i]._bExpanded){
                aOpened.push(this._aCards[i]._sName);
            }
        }
        
        oPreviewer.storeProp(this, 'opened_cards', aOpened.join(','));
    }
};


df.WebAccordionContainer.prototype.openCardsAfterRender = function(){
    var i, oTab, aOpened = [], sStored;
    
    sStored = oPreviewer.getProp(this, 'opened_cards');
    if(sStored){
        aOpened = sStored.split(',');
    }
    
    if(this.pbMultiOpen){
        for(i = 0; i < this._aCards.length; i++){
            oTab = this._aCards[i]; 
            if(oTab.pbExpanded || aOpened.indexOf(this._aCards[i]._sName) >= 0){
                this.showCard(oTab, false);
            }
        }
    }
};



