/* - - - - - - WebIFrame - - - - - - - - */
/*
Replace the openHtml method so that it generates a div instead of a real iframe. An iframe uses to 
much memory to be generated over and over again.

@param  aHtml   Array string builder to add HTML to.
@private
*/
df.WebIFrame.prototype.openHtml = function(aHtml){
    df.WebBaseControl.prototype.openHtml.call(this, aHtml); // Explicitly calling the openHtml method of the superclass
    
    aHtml.push('<div class="WebIFrm_Wrp"><div class="WebIFrm_Pseudo" style="height: 100%;"></div></div>');
};

/*
Replace the afterRender method so that it doesn't search for the iframe element that is not 
generated within the previewer.

@private
*/
df.WebIFrame.prototype.afterRender = function(){
    this._eControl = df.dom.query(this._eElem, "div.WebIFrm_Pseudo");
    this._eWrapper = df.dom.query(this._eElem, "div.WebIFrm_Wrp");
    
    df.WebBaseControl.prototype.afterRender.call(this); // Explicitly calling the openHtml method of the superclass
    
    this.set_pbShowBorder(this.pbShowBorder);
    this.set_psUrl(this.psUrl);
};


