insertRow(iRowIndexAfter) {
    this.oPrev.studioStartTransaction();

    for (let i = 0; i < this._oContainer._aChildren.length; i++) {
        let oChild = this._oContainer._aChildren[i];

        if (oChild.piRowIndex > iRowIndexAfter) {
            let iNewRowIndex = (oChild.piRowIndex + 1)
            oChild.set("piRowIndex", iNewRowIndex);
            this.oPrev.studioUpdateProp(oChild, "piRowIndex", iNewRowIndex);
        }else if(oChild.piRowIndex + oChild.piRowSpan - 1 > iRowIndexAfter){
            const iNewRowSpan = oChild.piRowSpan + 1;
            oChild.set("piRowSpan", iNewRowSpan);
            this.oPrev.studioUpdateProp(oChild, "piRowSpan", iNewRowSpan);
        }
    }
    // Keep grid's auto flow as is - let it fill gaps still
    // update psRowHeights, anything equal to or higher than inserted index needs to be shifted
    let [aRowHeights, iHighestRowNum] = this._oContainer.parsePsRowHeights();

    for (let r = 0; r < aRowHeights.length; r++)  {
        if (aRowHeights[r].iIndex > iRowIndexAfter) {
            aRowHeights[r].iIndex = (aRowHeights[r].iIndex + 1);
        }
    }

    // Rebuild psRowHeights
    const sRowTemplate = this.buildRowTemplate(aRowHeights);

    this.oObj.set("psRowHeights", sRowTemplate);
    this.oPrev.studioUpdateProp(this.oObj, "psRowHeights", ('"' + sRowTemplate + '"'));

    let aRows = this.determineRows(this.oObj);
    this.oPrev.studioUpdateProp(this.oObj, "piRowCount", aRows.length + 1);
    
    this.oPrev.studioEndTransaction();

    this.redrawGrid();
    
    return true;
}

removeRowInBetween (iRemoveIndex){
    let aRows = this.determineRows(this.oObj);

    if(aRows.length <= 1)
        return false;
    
    this.oPrev.studioStartTransaction();

    //  Move controls up
    for (let i = 0; i < this._oContainer._aChildren.length; i++) {
        let oChild = this._oContainer._aChildren[i];

        if (oChild.piRowIndex > iRemoveIndex) {
            const iNewRowIndex = (oChild.piRowIndex - 1)
            oChild.set("piRowIndex", iNewRowIndex);
            this.oPrev.studioUpdateProp(oChild, "piRowIndex", iNewRowIndex);
        } else if(oChild.piRowIndex + oChild.piRowSpan > iRemoveIndex){
            if (oChild.piRowSpan > 1){
                const iNewRowSpan = oChild.piRowSpan - 1;
                oChild.set("piRowSpan", iNewRowSpan);
                this.oPrev.studioUpdateProp(oChild, "piRowSpan", iNewRowSpan);
            }else if(oChild.piRowIndex > 0){
                const iNewRowIndex = (oChild.piRowIndex - 1)
                oChild.set("piRowIndex", iNewRowIndex);
                this.oPrev.studioUpdateProp(oChild, "piRowIndex", iNewRowIndex);
            }
        }
    }

    // Keep grid's auto flow as is - let it fill gaps still
    // update psRowHeights, anything equal to or higher than inserted index needs to be shifted
    let [aRowHeights, iHighestRowNum] = this._oContainer.parsePsRowHeights();

    for (let r = 0; r < aRowHeights.length; r++)  {
        if(aRowHeights[r].iIndex == iRemoveIndex){
            aRowHeights.splice(r, 1);
            r--;
        }else if (aRowHeights[r].iIndex > iRemoveIndex) {
            aRowHeights[r].iIndex = (aRowHeights[r].iIndex - 1);
        }
    }

    // Rebuild psRowHeights
    const sRowTemplate = this.buildRowTemplate(aRowHeights);
    this.oObj.set("psRowHeights", sRowTemplate);
    this.oPrev.studioUpdateProp(this.oObj, "psRowHeights", ('"' + sRowTemplate + '"'));
    
    // Reduce piRowCoutn    
    this.oPrev.studioUpdateProp(this.oObj, "piRowCount", aRows.length - 1);
    
    this.oPrev.studioEndTransaction();
    this.redrawGrid();

    return true;
}

