import { DesContainerEditor } from './WebAppDesignerContainerEditor.js';

export class DesCardEditor extends DesContainerEditor{
    
render(oObj){
    super.render();
    
    this.eDragMove = df.dom.create('<div class="prev_s_drag"></div>');
    this.eSelTop.appendChild(this.eDragMove);
    
    df.events.addDomListener("mousedown", this.eSelTop, this.onMove, this); 
    
    this.eButtons = df.generateCardButtons(this.oObj._oParent);
    this.eSel.appendChild(this.eButtons);
    
    df.dom.on("click", this.eButtons, this.onButtonClick, this);
}

position(oRect){
    super.position(...arguments);
    
    this.eButtons.style.top = (oRect.top - this.eButtons.offsetHeight - this.eSelTop.offsetHeight) + "px";
    this.eButtons.style.left = (oRect.left + oRect.width - this.eButtons.offsetWidth) + "px";
}

select(oObj){
    super.select(oObj);
    
    this.eButtons.innerHTML = df.generateCardButtonsContent(oObj._oParent);
}
    


onButtonClick(oEvent){
    var sName, eCur, eBtn = oEvent.getTarget();
    
    if(eBtn.hasAttribute("data-dfcard")){
        sName = eBtn.getAttribute("data-dfcard");
        
        if(this.oObj._oParent[sName]){
            this.oPrev.studioSelectObject(this.oObj._oParent[sName]);
        }
        
    }
}


initializeDrag(bCreate, oEv){
    var eMarker, oCardCon, oNextCard = null, oStartCardCon, oStartNextCard, oObj = this.oObj, i, iInitialY = 0, eButtonGhost, oButtonGhostCon;
    
    eMarker = df.dom.create('<div class="preview_insertmark"></div>');
    document.body.appendChild(eMarker);
    
    df.dom.addClass(document.body, "dragcursor");
    
    //  If dragging an existing tab we determine the initial values (CardCon, next sibbling and before)
    if(!bCreate){
        oStartCardCon = oObj._oParent;
        
        for(i = 0; i < oStartCardCon._aCards.length; i++){
            if(oStartCardCon._aCards[i] === oObj){
                if(i + 1 <  oStartCardCon._aCards.length){
                    oNextCard = oStartCardCon._aCards[i + 1];
                }
                
                break;
            }
        }
    }
    
    function hide(){
        oCardCon = null;
        oNextCard = null;
        eMarker.style.display = "none";
    }
    
    function move(iX, iY){
        var oRect, eElem, oHover = null, oCard, bBefore = false, eDesBtn = null, eDesBtns = null, eInsertElem, i, iAttempt = 2;
        
        //  Remember initial Y position
        if(!iInitialY){
            iInitialY = iY;
        }
        
        //  Find the tab button and control
        eElem = document.elementFromPoint(iX, iY);
        while(eElem && eElem !== document && !oHover && !eDesBtns){
            if(eElem === eMarker || eElem === this.eSel){
                return;
            }
            if(eElem.hasAttribute("data-dfcard")){
                eDesBtn = eElem;
            }
            if(eElem.hasAttribute("data-dfcontainer")){
                eDesBtns = eElem;
            }
            
            if(eElem.hasAttribute("data-dfobj")){
                oHover  = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
            }
            eElem = eElem.parentNode;
        }
        
        //  Find the tab container and optionally the tab page object
        oCardCon = null;
        while(oHover && !oCardCon){
            if(oHover instanceof df.WebCard && oHover._bCC){
                oCard = oHover;
            }
            if(oHover instanceof df.WebCardContainer && oHover._bCC){
                oCardCon = oHover;
            }
            oHover = oHover._oParent;
        }
        
        //  We are hovering a designer button
        if(eDesBtns){
            oCardCon = this.oPrev.findObj(eDesBtns.getAttribute("data-dfcontainer"));
            if(eDesBtn && oCardCon){
                oCard = oCardCon[eDesBtn.getAttribute("data-dfcard")];
            }
        }
        
        if(oCardCon){
            if(eDesBtn){    //  When hovering a tab button we will insert the tab before the tab that owns the button
                eInsertElem = eDesBtn;
                bBefore = true;
                oNextCard = oCard;
            }else if(eDesBtns){
                eInsertElem = eDesBtns.lastChild;
                bBefore = false;
                oNextCard = null;
                
            }else if(oCard){    //  When hovering the current tab itself we will insert the tab after the current tab
                eInsertElem = oCard._eElem;
                bBefore = false;
                
                i = oCardCon._aCards.indexOf(oCard) + 1;
                oNextCard = oCardCon._aCards[i] || null;
            }else{  //  When hovering just the tab container we will insert at the end
                oNextCard = null;
                if(oCardCon._oCurrent){
                    eInsertElem = oCardCon._oCurrent._eElem;
                }else{
                    eInsertElem = oCardCon._eBody;
                }
                bBefore = false;
            }
            
            if(this.oPrev._oCurrentWO !== oCardCon && (this.oPrev._oCurrentWO && this.oPrev._oCurrentWO._oParent) !== oCardCon){
                if(oButtonGhostCon !== oCardCon){
                    if(eButtonGhost){
                        eButtonGhost.style.display = "";
                        eButtonGhost.innerHTML = df.generateCardButtonsContent(oCardCon);
                    }else{
                        eButtonGhost = df.generateCardButtons(oCardCon);
                        document.body.appendChild(eButtonGhost);
                    }
                    oButtonGhostCon = oCardCon;
                }
                oRect = df.sys.gui.getBoundRect(oCardCon.getPreviewerElem());
                eButtonGhost.style.top = (oRect.top - eButtonGhost.offsetHeight) + "px";
                eButtonGhost.style.left = (oRect.left + oRect.width - eButtonGhost.offsetWidth) + "px";
            }else if(oButtonGhostCon){
                eButtonGhost.style.display = "none";
                oButtonGhostCon = null;
            }
            
            oRect = df.sys.gui.getBoundRect(eInsertElem);
                        
            //  Reposition marker
            eMarker.style.top = oRect.top + "px";
            eMarker.style.left = (bBefore ? oRect.left : oRect.right) + "px";
            eMarker.style.height = oRect.height + "px";
            
            eMarker.style.display = "";
        }else{
            //  If we are not hovering a CardCon we hide the insertion marker and clear the settings
            hide.call(this);
        }
    }
    
    function drop(sJsClassName){
        var sProps = "";
        
        if(oCardCon){
            if(bCreate){
                sProps = 'psCaption:"Card ' + (oCardCon._aCards.length + 1) + '"';
                this.oPrev.studioDropObject(sJsClassName, oCardCon, oNextCard, sProps);
            }else{
                //  If the newline changed for the newly inserted column we do that
                if(oStartCardCon !== oCardCon || oStartNextCard !== oNextCard){
                    this.oPrev.studioMoveObject(oObj, oCardCon, oNextCard, "");
                }
            }
        }
    }
    
    function end(){
        if(eMarker && eMarker.parentNode){
            eMarker.parentNode.removeChild(eMarker);
        }
        if(eButtonGhost && eButtonGhost.parentNode){
            eButtonGhost.parentNode.removeChild(eButtonGhost);
        }
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    return {
        move : move,
        drop : drop,
        end : end,
        hide : hide
    };
}




}


df.WebCard.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect){    
        if(!oEditor){
            oEditor = new DesCardEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());