import { DesUIObjectEditor } from './WebAppDesignerUIObjectEditor.js';

export class DesDDOEditor extends DesUIObjectEditor {
    
initializeDrag(bCreate, oEv){
    var oColEdit, oCtrlEdit, oColDrag, oCtrlDrag, bList = false;
    
    oColEdit = df.WebColumn.prototype.getEditor(this.oPrev);
    oCtrlEdit = df.WebBaseControl.prototype.getEditor(this.oPrev);
    
    function move(iX, iY){
        var oList = null;
    
        //  Determine list and column we are hovering
        Array.from(document.elementsFromPoint(iX, iY)).every((eElem) => {
            const eCtrl = eElem.closest("[data-dfobj]");

            if(eCtrl){
                const oCtrl = this.oPrev.findObj(eCtrl.dataset.dfobj);
                if( oCtrl instanceof df.WebList){
                    oList = oCtrl;
                }else if(oCtrl._bIsColum){
                    oList = oCtrl._oParent;
                }
                return false;
            }
            return true;

        });
        
        if(oList){
            if(oCtrlDrag && !bList){
                oCtrlDrag.hide.call(oCtrlEdit);
            }
            bList = true;
            if(!oColDrag){
                oColDrag = oColEdit.initializeDrag(bCreate);
            }
            
            oColDrag.move.call(oColEdit, iX, iY);
           
        }else{
            if(oColDrag && bList){
                oColDrag.hide.call(oColEdit);
            }
            bList = false;
            if(!oCtrlDrag){
                oCtrlDrag = oCtrlEdit.initializeDrag(bCreate);
            }
            
            oCtrlDrag.move.call(oCtrlEdit, iX, iY);
        }
    }
    
    function drop(sJsClassName){
        if(bList){
            oColDrag.drop.call(oColEdit, sJsClassName);
        }else{
            oCtrlDrag.drop.call(oCtrlEdit, sJsClassName);
        }
    }
    
    function end(){
        if(oColDrag){
            oColDrag.end.call(oColEdit);
            oColDrag = null;
        }
        oColEdit = null;
        
        if(oCtrlDrag){
            oCtrlDrag.end.call(oCtrlEdit);
            oCtrlDrag = null;
        }
        oCtrlEdit = null;
    }
    
    return {
        move : move,
        drop : drop,
        end : end
    };
}


}

df.getDDOEditor = (function(){
        var oEditor = null;
    
    return function(oPrev){    
        if(!oEditor){
            oEditor = new DesDDOEditor(oPrev);
        }
        
        return oEditor;
    };
}());