import { DesContainerEditor } from './WebAppDesignerContainerEditor.js';

export class DesFloatingPanelEditor extends DesContainerEditor{
    
render(oObj){
    super.render(oObj);

    this.eSelTop.appendChild(df.dom.create('<div class="prev_s_drag"></div>'));
    df.events.addDomListener("mousedown", this.eSelTop, this.onMove, this);
}

select(oObj){
    oObj.showDes(this.oPrev);

    super.select(oObj);
}

initializeDrag(bCreate, oEv){
    var eMarker, oStartPrnt, iLastX = -1, iLastY = -1, iStartX, iStartY, oPrnt = null, oStartNext  = null, oNext = null, oObj = this.oObj, iChild;
    
    eMarker = df.dom.create('<div class="preview_insertmark"></div>');
    document.body.appendChild(eMarker);
    
    df.dom.addClass(document.body, "dragcursor");
    
    //  Determine current position
    if(!bCreate){
        oStartPrnt = oPrnt = oObj._oParent;
        
        iChild = oPrnt._aUIObjects.indexOf(oObj);
        if(iChild < oPrnt._aUIObjects.length - 1){
            oStartNext = oNext = oPrnt._aUIObjects[iChild + 1];
        }
    }
        
    
    function move(iX, iY){
        var oCurRect, iTop, iHeight, eElem, oNewPrnt = null, oTestPrnt;
        
        if(iLastX < 0){
            iLastX = iStartX = iX;
            iLastY = iStartY = iY;
        }
    
        //  Determine if we are inside the current panel
        eElem = document.elementFromPoint(iX, iY);
        
        //  Find the container we are dragging into by inspecting the DOM
        while(eElem && eElem !== document && !(oNewPrnt && oNewPrnt._bIsContainer)){
            if(eElem.hasAttribute("data-dfobj")){
                oNewPrnt = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
            }
            eElem = eElem.parentNode;
        }

        //  Check if we are not dragging into the selected control itself (unless creating a new object)
        oTestPrnt = oNewPrnt;
        while(!bCreate && oTestPrnt){
            if(oTestPrnt === oObj){
                oNewPrnt = oObj._oParent;
            }
            
            oTestPrnt = oTestPrnt._oParent;
        }
        
        //  Check if we are hovering outside the view
        if(!oPrnt && !oNewPrnt && this.oPrev._bHasView){
            oNewPrnt = this.oPrev._aViews[0] || null;
        }
        if(!oPrnt && oNewPrnt instanceof df.WebBaseView){
            while(oNewPrnt && oNewPrnt._bPanels){
                oNewPrnt = oNewPrnt._oRegionCenter;
            }
        }
        
        if(oNewPrnt && oNewPrnt._bIsContainer && !oNewPrnt._bPanels){
            oCurRect = df.sys.gui.getBoundRect(oNewPrnt.getInsertionObject());
            
            //  Position marker
            iTop = oCurRect.top;
            iHeight = oCurRect.height;
            
            if(iHeight < 20){
                iTop = iTop - (10 - iHeight / 2);
                iHeight = 20;
            }
            
            eMarker.style.display = "";
            eMarker.style.top = iTop + "px";
            eMarker.style.height =  iHeight + "px";
            
            //eMarker.style.left = oCurRect.left + "px";
            
            eMarker.style.left = oCurRect.right + "px";
            
            oPrnt = oNewPrnt;

            return true;
        }
        
        return false;
    }
    
    function hide(){
        eMarker.style.display = "none";
    }
    
    function end(){
        if(eMarker && eMarker.parentNode){
            eMarker.parentNode.removeChild(eMarker);
        }
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    function drop(sJsClassName){
        if(bCreate){
            this.oPrev.studioDropObject(sJsClassName, oPrnt, null, "");
        }else{
            this.oPrev.studioMoveObject(oObj, oPrnt, null);
        }
    }
    
    return {
        end : end,
        drop : drop,
        move : move,
        hide : hide
    };
        
}

}

// Plug into the inheritance structure
df.WebFloatingPanel.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesFloatingPanelEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());

export class WebFloatingPanel_Designer extends df.WebFloatingPanel{

create(){
    super.create();

    this.pbHideOnBlur = false;
    this.pbHideOnEscape = false;
}

showDes(oDes){
    oDes.onSelectedChange.addListener(this.onDesignerSelectedChange, this);

    this.show();
}

hideDes(oDes){
    oDes.onSelectedChange.removeListener(this.onDesignerSelectedChange);

    this.hide();
}

onDesignerSelectedChange(oEv){
    if(this._bVisible){
        if(oEv.oNewObj && oEv.oNewObj !== this && !oEv.oNewObj.isParent(this)){
            this.hideDes(oEv.oSource);
        }
    }
}

}

// Plug into the inheritance structure
df.WebFloatingPanel.prototype.getDesignerClass = function(sType){
    return WebFloatingPanel_Designer;
};