import { DesObjectEditor } from './WebAppDesignerObjectEditor.js';
//import { WebFloatingPanel_Designer } from './WebAppDesignerFloatingPanel.js';
//import { WebContextMenu_Designer } from './WebAppDesignerContextMenu.js';

export class DesUIObjectEditor extends DesObjectEditor {

constructor(oPrev) {
    super(oPrev);

    this.sSelectorClassName = "";
    this.fRepositionTimer = null;
    this.bAutoRepos = true;
}

select(oObj){
    var ePrev;
    
    super.select(oObj);
    
    if(oObj){
        this.makeVisible(oObj)
    }
    
    ePrev = this.getPreviewerElem();
    
    if(!this.eSel){
        this.render(oObj);
    }
    
    
    if(ePrev){
        this.reposition();
    }

    this.oObj.OnAfterShow.addListener(this.onAfterObjShow, this);
    this.oObj.OnAfterHide.addListener(this.onAfterObjHide, this);
    
    if(ePrev){
        let oPrevRect = ePrev.getBoundingClientRect();
        if (this.fRepositionTimer) clearInterval(this.fRepositionTimer);
        this.fRepositionTimer = setInterval(() =>{
            if(!ePrev) return;

            if(this.bAutoRepos){
                //  Only continue if there are changes
                let oNewRect = ePrev.getBoundingClientRect();
                if(oPrevRect.x == oNewRect.x && oPrevRect.y == oNewRect.y && oPrevRect.width == oNewRect.width && oPrevRect.height == oNewRect.height){
                    return;
                } 

                oPrevRect = oNewRect;
                this.reposition();
            }
        }, 100);
    }
}

unselect(oNewSel){
    super.unselect(oNewSel);

    if(this.eSel){
        this.eSel.style.display = "none";
    }
    
    if(this.oObj){
        this.oObj.OnAfterShow.removeListener(this.onAfterObjShow);
        this.oObj.OnAfterHide.removeListener(this.onAfterObjHide, this);
    }

    if(this.fRepositionTimer){
        clearInterval(this.fRepositionTimer);
        this.fRepositionTimer = null;
    }
}

onAfterObjShow(){
    this.reposition();
}


onAfterObjHide(){
    this.reposition();
}


render(oObj){
    var eSel;
    
    this.eSel = eSel = df.dom.create('<div class="preview_selected ' + this.sSelectorClassName + '" style="display: none"><div class="prev_s_top"></div><div class="prev_s_right"></div><div class="prev_s_left"></div><div class="prev_s_bottom"></div></div>');
    
    this.eSelTop = df.dom.query(eSel, 'div.prev_s_top');
    this.eSelLeft = df.dom.query(eSel, 'div.prev_s_left');
    this.eSelBottom = df.dom.query(eSel, 'div.prev_s_bottom');
    this.eSelRight = df.dom.query(eSel, 'div.prev_s_right');
    
    this.oPrev._eRenderTo.parentNode.appendChild(eSel);
}

reposition(){
    var eElem;
    
    if(this.eSel && this.oObj){
        eElem = this.getPreviewerElem();
        
        if(eElem && this.oObj._bShown && df.sys.gui.isOnScreen(eElem)){
            this.position(df.sys.gui.getBoundRect(eElem));
        }else{
            this.eSel.style.display = "none";
        }
    }
    
}

position(oRect){
    this.eSel.style.display = "";
    
    this.eSelLeft.style.top = Math.round(oRect.top)  + "px";
    this.eSelLeft.style.left = Math.round(oRect.left) + "px";
    this.eSelLeft.style.height = Math.round(oRect.height) + "px";
    
    this.eSelTop.style.top = oPreviewer.calcTop(oRect.top) + "px";
    this.eSelTop.style.left = Math.round(oRect.left) + "px";
    this.eSelTop.style.width = Math.round(oRect.width) + "px";
    
    this.eSelBottom.style.top = (Math.round(oRect.top) + Math.round(oRect.height) - this.eSelBottom.offsetHeight) + "px";
    this.eSelBottom.style.left = Math.round(oRect.left) + "px";
    this.eSelBottom.style.width = Math.round(oRect.width) + "px";
    
    this.eSelRight.style.top = Math.round(oRect.top) + "px";
    this.eSelRight.style.left = (Math.round(oRect.left) + Math.round(oRect.width)- this.eSelRight.offsetWidth) + "px";
    this.eSelRight.style.height = Math.round(oRect.height) + "px";
}

onMove(oEv){
    var oDrag = this.initializeDrag(false, oEv);
    
    function onMove(oEv){
        oDrag.move.call(this, oEv.getMouseX(), oEv.getMouseY());
    }
    
    function onStopMove(oEv){
        df.events.removeDomListener("mouseup", window, onStopMove, this);
        df.events.removeDomListener("mousemove", document, onMove, this);

        oDrag.drop.call(this);
        oDrag.end.call(this);
        
        oDrag = null;
    }
    
        
    df.events.addDomListener("mousemove", document, onMove, this);
    df.events.addDomListener("mouseup", window, onStopMove, this);
    
    oDrag.move.call(this, oEv.getMouseX(), oEv.getMouseY());
    
    oEv.stop();
}

getPreviewerElem(){
    return (this.oObj && this.oObj.getPreviewerElem()) || null;
}

makeVisible(oObj){
    //  Call standard framework make visible that handles tab pages
    oObj.makeVisible();

    while(oObj){
        oObj.showDes?.(this.oPrev);
        
        oObj = oObj._oParent;
    }
}

}


df.WebBaseUIObject.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesUIObjectEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());