
export class GridEditPopup{
    components = {
        eWindow: null,
        eValFixed : null,
        eValFraction: null,
        eValCustom : null,
    };

    display(oConfig){
        if(this.components.eWindow){
            this.close();
        }

        this.bRow = !!oConfig.bRow;
        this.iIndex = oConfig.iIndex || 0;
        this.eType = oConfig.eType || df.rowColValType.ciTypeDefault;
        this.iValFraction = oConfig.iValFraction || 1;
        this.iValFixed = oConfig.iValFixed || 1;
        this.sValOther = oConfig.sValOther || "";
        this.sValDefault = oConfig.sValDefault || "-1";

        this.fOnRemove = oConfig.fOnRemove || null;
        this.fOnInsertBefore = oConfig.fOnInsertBefore || null;
        this.fOnInsertAfter = oConfig.fOnInsertAfter || null;


        this.fOnSave = oConfig.fOnSave || null;
        this.fOnClose = oConfig.fOnClose || null;

        const eWin = this.components.eWindow = window.open('https://locallib.asset/WebAppDesignerGridMenu.html', '_blank', "left=200,top=200,width=400,height=250");
        eWin.addEventListener("load", this.onInitialize.bind(this));
    }

    onInitialize(e){
        const eDoc = this.components.eWindow.document;
                
        //  Set Title
        eDoc.title = `Grid ${this.bRow ? 'row' : 'column'} ${this.iIndex} settings`;

        //  Generate HTML contents
        let aHtml = [];
        aHtml.push('<div class="prev_gridOverlay_edit_menu_wrp">');

        //aHtml.push('    <div class="prev_gridOverlay_edit_menu_header">Editing row index: <span id="menu-index">' , iIndex + '</span></div>');
        aHtml.push('<div class="prev_gridOverlay_values">');
        if(this.bRow){
            aHtml.push('    <h1>Height</h1>')
        }else{
            aHtml.push('    <h1>Width</h1>')
        }
        aHtml.push('    <div class="prev_gridOverlay_form_grp">');
        aHtml.push('        <input type="radio" name="rowcol-type" id="rowcol-type-radio-default" value="', df.rowColValType.ciTypeDefault, '" ', ((this.eType == df.rowColValType.ciTypeDefault) ? 'checked' : ''), ' />');
        aHtml.push('        <label for="rowcol-type-radio-default"/>Default</label>');
        aHtml.push('    </div>');

        aHtml.push('    <div class="prev_gridOverlay_form_grp">');
        aHtml.push('        <input type="radio" name="rowcol-type" id="rowcol-type-radio-fixed" value="', df.rowColValType.ciTypeFixed, '" ', ((this.eType == df.rowColValType.ciTypeFixed) ? 'checked' : ''), ' />');
        aHtml.push('        <label for="rowcol-type-radio-fixed"/>Fixed (px)</label>');
        aHtml.push('    </div>');
        
        aHtml.push('    <div class="prev_gridOverlay_form_grp">');
        aHtml.push('        <input type="radio" name="rowcol-type" id="rowcol-type-radio-fraction" value="', df.rowColValType.ciTypeFraction, '" ', ((this.eType == df.rowColValType.ciTypeFraction) ? 'checked' : ''), ' />');
        aHtml.push('        <label for="rowcol-type-radio-fraction"/>Fraction (fr)</label>');
        aHtml.push('    </div>');
        
        aHtml.push('    <div class="prev_gridOverlay_form_grp">');
        aHtml.push('        <input type="radio" name="rowcol-type" id="rowcol-type-radio-other" value="', df.rowColValType.ciTypeOther, '" ', ((this.eType == df.rowColValType.ciTypeOther) ? 'checked' : ''), ' />');
        aHtml.push('        <label for="rowcol-type-radio-other"/>Other</label>');
        aHtml.push('    </div>')
        aHtml.push('    <div class="prev_gridOverlay_form_grp">');
        aHtml.push('        <input type="text" id="edit-value-form-fixed" value="', this.iValFixed, '" ', (this.eType != df.rowColValType.ciTypeFixed ? 'style="display: none"' : ''), '/>');
        aHtml.push('        <input type="text" id="edit-value-form-fraction" value="', this.iValFraction, '" ', (this.eType != df.rowColValType.ciTypeFraction ? 'style="display: none"' : ''), '/>');
        aHtml.push('        <input type="text" id="edit-value-form-other" value="', this.sValOther, '" ', (this.eType != df.rowColValType.ciTypeOther ? 'style="display: none"' : ''), '/>');
        aHtml.push('    </div>');

        aHtml.push('</div>')

        aHtml.push('    <div class="prev_gridOverlay_row_button_wrp">');
        if(this.bRow){
            aHtml.push('        <button id="insert-before-btn" class="prev_gridAction icon_grid_add_row">Insert row above</button>');
            aHtml.push('        <button id="remove-btn" class="prev_gridAction icon_grid_remove_row">Remove row</button>');
            aHtml.push('        <button id="insert-after-btn" class="prev_gridAction icon_grid_add_row">Insert row below</button>');
        }else{
            aHtml.push('        <button id="insert-before-btn" class="prev_gridAction icon_grid_add_column">Insert column before</button>');
            aHtml.push('        <button id="remove-btn" class="prev_gridAction icon_grid_remove_column">Remove column</button>');
            aHtml.push('        <button id="insert-after-btn" class="prev_gridAction icon_grid_add_column">Insert column after</button>');
        }
        aHtml.push('    </div>');

        aHtml.push('    <div class="prev_gridOverlay_button_wrp">');
        aHtml.push('        <span id="cancel-btn" class="rowcol-edit-cancel-btn">Cancel</span>');
        aHtml.push('        <input id="save-btn" type="button" value="Save">');
        aHtml.push('    </div>');

        aHtml.push('    </div>');

        eDoc.body.innerHTML = aHtml.join('');

        eDoc.getElementById("save-btn").addEventListener("click", this.onSaveClick.bind(this));
        eDoc.getElementById("cancel-btn").addEventListener("click", this.onCancelClick.bind(this));

        eDoc.getElementById("insert-before-btn").addEventListener("click", this.onInsertBeforeClick.bind(this));
        eDoc.getElementById("remove-btn").addEventListener("click", this.onRemoveClick.bind(this));
        eDoc.getElementById("insert-after-btn").addEventListener("click", this.onInsertAfterClick.bind(this));

        eDoc.querySelectorAll('input[type="radio"]').forEach((eElem) => eElem.addEventListener("change", this.onRadioChange.bind(this)));

        this.components.eValFixed = eDoc.getElementById("edit-value-form-fixed");
        this.components.eValFraction = eDoc.getElementById("edit-value-form-fraction");
        this.components.eValOther = eDoc.getElementById("edit-value-form-other");
        this.components.eWindow.addEventListener("beforeunload", this.onWindowClose.bind(this));
    }

    onRemoveClick(e){
        if(this.fOnRemove?.(this.iIndex)){
            this.close();
        }
    }
    onInsertBeforeClick(e){
        const iOrigIndex = this.iIndex;
        this.iIndex++;
        if(this.fOnInsertBefore?.(iOrigIndex)){
            this.components.eWindow.document.title = `Grid ${this.bRow ? 'row' : 'column'} ${this.iIndex} settings`;
        }else{
            this.iIndex = iOrigIndex;
        }
    }

    onInsertAfterClick(e){
        this.fOnInsertAfter?.(this.iIndex);
    }

    onSaveClick(e){
        let sVal = "";
        switch(this.eType){
            case df.rowColValType.ciTypeDefault:
                sVal = this.sValDefault;
                break;
            case df.rowColValType.ciTypeFixed:
                sVal = this.components.eValFixed.value;
                break;
            case df.rowColValType.ciTypeFraction:
                sVal = this.components.eValFraction.value;
                break;
            case df.rowColValType.ciTypeOther:
                sVal = this.components.eValOther.value;
                break;
        }

        this.fOnSave?.(this.iIndex, this.eType, sVal);
        this.close();
    }
    onWindowClose(e){
        this.close(true);
    }
    onCancelClick(e){
        this.close();
    }
    onRadioChange(e){
        this.eType = parseInt(e.target.value);
        
        this.components.eValFixed.style.display = (this.eType == df.rowColValType.ciTypeFixed ? '' : 'none');
        this.components.eValFraction.style.display = (this.eType == df.rowColValType.ciTypeFraction ? '' : 'none');
        this.components.eValOther.style.display = (this.eType == df.rowColValType.ciTypeOther ? '' : 'none');

        switch(this.eType){
            case df.rowColValType.ciTypeFixed:
                this.components.eValFixed.focus();
                break;
            case df.rowColValType.ciTypeFraction:
                this.components.eValFraction.focus();
                break;
            case df.rowColValType.ciTypeOther:
                this.components.eValOther.focus();
                break;
        }
    }

    displayed(){
        return !!this.components.eWindow;
    }

    currentIndex(){
        return this.iIndex;
    }

    currentIsRow(){
        return this.bRow;
    }

    close(bOptNoClose){
        if(this.components.eWindow){
            if(!bOptNoClose){
                this.components.eWindow.close();
            }
            this.components = {
                eWindow: null,
                eValFixed : null,
                eValFraction: null,
                eValCustom : null,
            };
            this.fOnClose?.(this.bRow, this.iIndex);
        }

        this.iIndex = null;
    }

}