import { DesFloatingPanelEditor } from './WebAppDesignerFloatingPanel.js';

/* 
Editor for the ExpandPanel. Has its own drag logic and extra hooks in the list to handle scrolling.
*/
export class DesContextMenuEditor extends DesFloatingPanelEditor{

}
df.WebContextMenu.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesContextMenuEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());

/* 
Designer class for the ExpandPanel that makes sure it is always rendered.
 */
export class WebContextMenu_Designer extends df.WebContextMenu{

create(){
    super.create();
    this._oMenu.onMenuClick = this._fMenuBaseClick;
    
    this.pbHideOnBlur = false;
    this.pbHideOnEscape = false;
    this.piLeft = 0;
    this.piTop = 0;
}

onContextMenuOpen(oEvent){}

bind() { /* stub */ }

unbind() { /* stub */ }

showDes(oDes){
    oDes.onSelectedChange.addListener(this.onDesignerSelectedChange, this);

    this.show();
}

hideDes(oDes){
    oDes.onSelectedChange.removeListener(this.onDesignerSelectedChange);

    this.hide();
}

onDesignerSelectedChange(oEv){
    if(this._bVisible){
        if(oEv.oNewObj && oEv.oNewObj !== this && !oEv.oNewObj.isParent(this)){
            this.hideDes(oEv.oSource);
        }
    }
}

}

df.WebContextMenu.prototype.getDesignerClass = function(sType){
    return WebContextMenu_Designer;
};