import { DesUIObjectEditor } from './WebAppDesignerUIObjectEditor.js';
import { WebContextMenu_Designer } from './WebAppDesignerContextMenu.js';
import { DesControlEditor } from './WebAppDesignerControlEditor.js';

export class DesMenuItemEditor extends DesUIObjectEditor{

constructor(oPrev){
    super(oPrev);
    
    this.oMnu = null;
}

select(oObj){
    super.select(oObj);
    
    var tItm, oMnu;
    
    this.oMnu = oMnu = this.guessMenu();
    
    if(oMnu){
        tItm = oMnu.getItemByHandler(this.oObj);
        
        if(tItm){
            //if(tItm.aChildren.length === 0){
                //tItm = oMnu.getItemByPath(tItm._sPath.substr(0, tItm._sPath.lastIndexOf(".")));
            //}
            if(tItm){   
                oMnu.showItem(tItm);
            }else{
                oMnu.collapseAll();
            }
            
        }
        
        oMnu.OnUiUpdate.addListener(this.onMenuUpdate, this);
    }
}

unselect(oNewSel){
    super.unselect.apply(this, arguments);
    
    if(this.oMnu){
        this.oMnu.OnUiUpdate.removeListener(this.onMenuUpdate, this);
    }
}


getPreviewerElem(){
    var tItm, oMnu = this.guessMenu();
    
    if(oMnu instanceof df.WebMenuButton){
        oMnu.showMenu();
        oMnu = this.guessMenu();
    }
    
    if(oMnu){
        tItm = oMnu.getItemByHandler(this.oObj);
        
        if(tItm){
            return oMnu.getItemElemByPath(tItm._sPath);
        }
    }
}

guessMenu(){
    var oHub, tGrp, oProv = this.oObj.getProv();
    
    if(oProv){
        if(oProv.psGroupName){
            oHub = oProv.getHub();
            if(oHub){
                tGrp = oHub._oGroups[oProv.psGroupName.toLowerCase()];
            
            
                // for(i = 0; i < tGrp.aListeners.length; i++){
                    // oMnu = tGrp.aListeners[i];
                    
                    // return oMnu;
                // }
                
                if(tGrp && tGrp.aListeners.length > 0){
                    return tGrp.aListeners[0];
                }
                if(tGrp && tGrp.aProviders.length > 0){   //  In case of the menu button there is not always a listener as it might not have initialized itself
                    return tGrp.aProviders[0];
                }
                
                return null;
            }
        } else if (oProv instanceof WebContextMenu_Designer) {
            return oProv._oMenu;
        } else {
            return oProv;
        }
    }
}

onMenuUpdate(oEvent){
    this.reposition();
}

}


df.WebMenuItem.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesMenuItemEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());


/* 

*/
df.WebMenuBar.prototype.getEditor = (function(){
    var oConEdit = null, oUIEdit;
    
    return function(oPrev){ 
        var oEditor;
        
        if(this._oParent instanceof df.WebCommandBar){
            if(!oUIEdit){
                oUIEdit = new DesUIObjectEditor(oPrev);
            }
            oEditor = oUIEdit;
        }else{
            if(!oConEdit){
                oConEdit = new DesControlEditor(oPrev);
            }
            oEditor = oConEdit;
        }
        
        if(this._bIsWO){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());