import { DesUIObjectEditor } from './WebAppDesignerUIObjectEditor.js';
/* global df */

export class DesColumnEditor extends DesUIObjectEditor{

render(oObj){
    super.render(...arguments);
    
    //  Add resizer
    this.eResizer = df.dom.create('<div class="prev_s_resizehoriz"></div>');
    this.eSelTop.appendChild(this.eResizer);
    
    df.events.addDomListener("mousedown", this.eResizer, this.onResize, this);    
    
    //  Add dragging dots
    this.eSelTop.appendChild(df.dom.create('<div class="prev_s_drag"></div>'));
    df.events.addDomListener("mousedown", this.eSelTop, this.onMove, this);
}

initializeDrag(bCreate, oEv){
    var eMarker, oList, oNextCol, oStartList, oStartNextCol, bStartNewLine = false, oObj = this.oObj, iCol, bNewLine = false, aLayoutToMapperIndex = [], iVisibleCol;
    
    eMarker = df.dom.create('<div class="preview_insertmark"></div>');
    document.body.appendChild(eMarker);
    
    df.dom.addClass(document.body, "dragcursor");

    //  If dragging an existing column we determine the initial values (list, next sibbling and before)
    if(!bCreate){
        oStartList = oObj._oParent;
        if(oStartList._aColumns.length > 1){
            iCol = oObj._iCol;
            if(iCol < oStartList._aColumns.length - 1){
                oStartNextCol = oStartList._aColumns[iCol + 1];
            }else{
                oStartNextCol = null;
            }
        }
        bStartNewLine = oObj.pbNewLine;
    }
    
    function hide(){
        oList = null;
        oNextCol = null;
        aLayoutToMapperIndex = [];
        eMarker.style.display = "none";
    }
    
    function move(iX, iY){
        var oRect, eElem, oHover = null, iCol = null, oNewCol, bBefore = false;
    
        //  Determine list and column we are hovering
        eElem = document.elementFromPoint(iX, iY);
        
        //  Find control we are hovering
        while(eElem && eElem !== document && !(oHover)){
             if(eElem === eMarker || eElem === this.eSel){
                return;
            }
            
            if(eElem.hasAttribute("data-dfcol")){
                iCol = df.toInt(eElem.getAttribute("data-dfcol"));
                iVisibleCol =  Array.prototype.indexOf.call(eElem.parentNode.children, eElem);
            }
            if(eElem.hasAttribute("data-dfobj")){
                oHover  = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
            }
            eElem = eElem.parentNode;
        }
        
        //  Find list object
        oList = null;
        while(oHover && !oList){
            if(oHover instanceof df.WebList){
                oList = oHover;
            }
            oHover = oHover._oParent;
        }
        
        bNewLine = false;
        if(oList){
            aLayoutToMapperIndex = [];
            for (let i = 0; i < oList._aColumnMapper.length; i++) {
                if (oList._aColumnMapper[i].pbRender && !oList._aColumnMapper[i].pbHidden) {
                    aLayoutToMapperIndex.push(i);
                }
            }


            //  Find the column we are hoverign
            if(iVisibleCol !== null){
                iCol = aLayoutToMapperIndex[iVisibleCol];
                oNewCol = oList._aColumns[iCol];
            }
            
            //  Determine insertion rectange
            if(oNewCol){
                //  If a column is being hovered we insert before or after the column
                oRect = df.sys.gui.getBoundRect(oNewCol.getPreviewerElem());
                
                //  Determine if we should insert before or after the hovered column and determine the next column based on that
                bBefore = (iX - oRect.left < oRect.width * 0.4);
                if(bBefore){
                    oNextCol = oNewCol;
                    bNewLine = oNextCol.pbNewLine;
                }else{
                    oNextCol = (iCol < oList._aColumns.length - 1 ? oList._aColumns[iCol + 1] : null);
                }
            }else{
                //  If a list is being hovered we show the insertion point as the end of header (or the list if not shown)
                if(oList.pbShowHeader){
                    oRect = df.sys.gui.getBoundRect(oList._oHeader.eHead);
                }else{
                    if(oList._oBody.bScroll){
                        oRect = df.sys.gui.getBoundRect(oList._oBody.eTable.firstChild || oList._oBody.eTable);
                    }else{
                        oRect = df.sys.gui.getBoundRect(oList._oBody.eBody.firstChild || oList._oBody.eBody);
                    }
                }
                
                oNextCol = null;
            }
            
            //  Reposition marker
            eMarker.style.top = oRect.top + "px";
            eMarker.style.left = (bBefore ? oRect.left : oRect.right) + "px";
            eMarker.style.height = oRect.height + "px";
            
            eMarker.style.display = "";
        }else{
            //  If we are not hovering a list we hide the insertion marker and clear the settings
            hide.call(this);
        }
    }
    
    function drop(sJsClassName){
        var sProps = "";
        
        this.oPrev.studioStartTransaction();
        
        //  Funky logic for pbNewLine
        
        //  If the column started with pbNewLine we assume that has to move to the next column
        if(bStartNewLine){
            if(oStartNextCol){
                this.oPrev.studioUpdateProp(oStartNextCol, "pbNewLine", "True");
            }
        }
        //  If we insert before a column with pbNewLine we assume that has to move to the column being dropped
        if(bNewLine){
            if(oNextCol && oNextCol.pbNewLine){
                this.oPrev.studioUpdateProp(oNextCol, "pbNewLine", "False");
            }
        }
        
        if(bCreate){
            //  Pass newline as property for the created object
            if(bNewLine && sJsClassName !== "DDOExplorer"){
                sProps = "pbNewLine:True";
            }
            this.oPrev.studioDropObject(sJsClassName, oList, oNextCol, sProps);
        }else{
            //  If the newline changed for the newly inserted column we do that
            if(bStartNewLine !== bNewLine){
                this.oPrev.studioUpdateProp(oObj, "pbNewLine", (bNewLine ? "True" : "False"));
            }
            if(oStartList !== oList || oStartNextCol !== oNextCol){
                this.oPrev.studioMoveObject(oObj, oList, oNextCol, "");
            }
        }
        
        this.oPrev.studioEndTransaction();
    }
    
    function end(){
        if(eMarker && eMarker.parentNode){
            eMarker.parentNode.removeChild(eMarker);
        }
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    return {
        move : move,
        drop : drop,
        end : end,
        hide : hide
    };
}


onResize(oEv){
    var eMask, eElem, oRect, iStartWidth, iStartMouseX, iRightOffsetWidth, iWidth,  
        oObj = this.oObj, oL = oObj._oParent, iCol, iVCol, i, iMin, iMax, iRatio, iPX, oR = oL._oRowRenderer;

    this.bAutoRepos = false;
    
    //  Initialize dragMask
    eMask = df.gui.dragMask();
    eMask.style.cursor = "e-resize";
    
    //  Calculate initials
    eElem = oObj.getPreviewerElem();
    oRect = df.sys.gui.getBoundRect(eElem);
    
    iStartMouseX = oEv.getMouseX();
    iStartWidth = oRect.width;
    
    iRightOffsetWidth = this.eSelRight.offsetWidth;
    
        
    //  Determine percentage to pixel ratio
    iCol = oObj._iCol;
    iVCol = oR.findVColNr(oObj);
    iRatio = oR.calcPixelRatio(iCol);
    
    //  Determine current position and maximum
    iMax = 0;
    if(oL.pbAutoColumnSizing){
        for(i = iVCol; i < oR.aColWidths.length; i++){
            if(oR.aColWidths[i].oCol.piListRowSpan <= 1 || oR.aColWidths[i].oCol._iCol > iCol ){
                
                if(oR.aColWidths[i].bFixed){
                    iPX = oR.aColWidths[i].iPixels;
                }else{
                    iPX = (oR.aColWidths[i].iPercent * iRatio);
                }
            
                //    Determine maximum
                iMax += iPX - oR.iColMin;
            }
        }
    }else{
        iMax = screen.width - oRect.left;
    }
    
    iMin = oR.iColMin;
       
    function onResize(oEv){
        var iOffset; 
        
        //  Calculate width based on mouse position and min and max
        iOffset = oEv.getMouseX() - iStartMouseX;
        iWidth = iStartWidth + iOffset;
        
        if(iWidth < iMin){
            iWidth = iMin;
        }else if(iWidth > iMax){
            iWidth = iMax;
        }
        
        //  Update selection
        this.eSelTop.style.width = iWidth + "px";
        this.eSelBottom.style.width = iWidth + "px";
        this.eSelRight.style.left = (oRect.left + iWidth - iRightOffsetWidth) + "px";
    
        
    }
    
    function onStopResize(oEv){
        var i, aWidths = [], oCol;
        
        //  Store current column widths
        for(i = 0; i < oR.aColWidths.length; i++){
            aWidths.push(Math.floor(oR.aColWidths[i].piWidth));
        }
        
        //  Do recalculate column sizes (reuse existing list function for this)
        oR.recalcColumnSizes(iVCol, iWidth - iStartWidth, true);
        oL.redraw();
        
        //  Update all changed column widths in a single transaction
        this.oPrev.studioStartTransaction();
        for(i = 0; i < oR.aColWidths.length; i++){
            oCol = oR.aColWidths[i].oCol;
            if(aWidths[i] !== Math.floor(oCol.piWidth)){
                this.oPrev.studioUpdateProp(oCol, "piWidth", Math.floor(oCol.piWidth));
            }
        }
        this.oPrev.studioEndTransaction();
        
        //  Cleanup
        df.events.removeDomListener("mouseup", eMask, onStopResize, this);
        df.events.removeDomListener("mouseup", window, onStopResize, this);
        df.events.removeDomListener("mousemove", eMask, onResize, this);
        
        if(eMask && eMask.parentNode){
            eMask.parentNode.removeChild(eMask);
        }
        
        this.bAutoRepos = true;
    }
    
    df.events.addDomListener("mousemove", eMask, onResize, this);
    df.events.addDomListener("mouseup", window, onStopResize, this);
    df.events.addDomListener("mouseup", eMask, onStopResize, this);
        
    oEv.stop();
}

reposition(){
    var i, oObj = this.oObj, oL, bRes = false, oR;
    
    if(oObj){
        oL = oObj._oParent;
        oR = oL._oRowRenderer;
        
        if(!(oL instanceof df.WebHtmlList)){    //  No column resizing supported on htmllist
            //  Only resize columns that actually determine the width of a virtual column and are not the last column (unless we are not auto column sizing)
            for(i = 0; i < oR.aColWidths.length - (oL.pbAutoColumnSizing ? 1 : 0); i++){
                if(oR.aColWidths[i].oCol === oObj){
                    bRes = true;
                }
            }
        }
        //  Hide resizer based on findings
        this.eResizer.style.display = (bRes ? "" : "none");
    }
    
    super.reposition(...arguments);
}

}


df.WebColumn.prototype.getEditor = 
df.WebColumnButton.prototype.getEditor = 
df.WebColumnCheckbox.prototype.getEditor = 
df.WebColumnCombo.prototype.getEditor = 
df.WebColumnDate.prototype.getEditor = 
df.WebColumnImage.prototype.getEditor = 
df.WebColumnLink.prototype.getEditor = 
df.WebColumnTags.prototype.getEditor = 
df.WebColumnSuggestion.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev){    
        if(!oEditor){
            oEditor = new DesColumnEditor(oPrev);
        }
        
        if(this._bIsWO){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());