import { DesContainerEditor } from './WebAppDesignerContainerEditor.js';

export class DesExpandPanelEditor extends DesContainerEditor{
    
render(oObj){
    super.render(oObj);

    this.eSelTop.appendChild(df.dom.create('<div class="prev_s_drag"></div>'));
    df.events.addDomListener("mousedown", this.eSelTop, this.onMove, this);
}

initializeDrag(bCreate, oEv){
    var eMarker, oList, oObj = this.oObj;
    
    eMarker = df.dom.create('<div class="preview_insertmarkhorizontal"></div>');
    document.body.appendChild(eMarker);
    
    df.dom.addClass(document.body, "dragcursor");
    
   
    function hide(){
        oList = null;
        eMarker.style.display = "none";
    }
    
    function move(iX, iY){
        var oRect, eElem, oHover = null;
    
        //  Determine list and column we are hovering
        eElem = document.elementFromPoint(iX, iY);
        
        //  Find control we are hovering
        while(eElem && eElem !== document && !(oHover)){
             if(eElem === eMarker || eElem === this.eSel){
                return;
            }
            if(eElem.hasAttribute("data-dfobj")){
                oHover  = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
            }
            eElem = eElem.parentNode;
        }
        
        //  Find list object
        oList = null;
        while(oHover){
            if(oHover instanceof df.WebList){
                oList = oHover;
            }
            //  Make sure we do not insert the panel into ourselves
            if(!bCreate && oHover == this.oObj){
                oList = null;
            }
            oHover = oHover._oParent;
        }
        
        if(oList){
            if(oList._oBody.bScroll){
                oRect = df.sys.gui.getBoundRect(oList._oBody.eTable);
            }else{
                oRect = df.sys.gui.getBoundRect(oList._oBody.eBody);
            }
            
            //  Reposition marker
            eMarker.style.top = oRect.top + "px";
            eMarker.style.left = oRect.left + "px";
            eMarker.style.width = oRect.width + "px";
            
            eMarker.style.display = "";
        }else{
            //  If we are not hovering a list we hide the insertion marker and clear the settings
            hide.call(this);
        }
    }
    
    function drop(sJsClassName){
        var sProps = "";
        
        this.oPrev.studioStartTransaction();
        
        if(bCreate){
            this.oPrev.studioDropObject(sJsClassName, oList, null, sProps);
        }else{
            this.oPrev.studioMoveObject(oObj, oList, null, "");
        }
        
        this.oPrev.studioEndTransaction();
    }
    
    function end(){
        if(eMarker && eMarker.parentNode){
            eMarker.parentNode.removeChild(eMarker);
        }
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    return {
        move : move,
        drop : drop,
        end : end,
        hide : hide
    };
}

}

// Plug into the inheritance structure
df.WebListExpandPanel.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesExpandPanelEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());

/* 
Designer class for the ExpandPanel that makes sure it is always rendered.
 */
class WebListExpandPanel_Designer extends df.WebListExpandPanel{


constructor(sName, oPrnt){
    super(sName, oPrnt);

    this._bInitialized = false;
}

create(){
    super.create.call(this);

    this.peMode = df.wleManual;
}

onRowsRendered(oEv){
    super.onRowsRendered.call(this, oEv);

    //  Expand on preview row
    if(!this._sExpandedRow){
        this.expand("preview_0");
    }
}

}

// Plug into the inheritance structure
df.WebListExpandPanel.prototype.getDesignerClass = function(sType){
    return WebListExpandPanel_Designer;
};