/*
Class:
    df.DesObjectEditor
Extends:
    df.WebApp

This is the highest level designer class for the designer. It contains the basic API for designer 
classes and is used to edit WebObject objects that don�t have a more specific designer class. 
Important are select and unselect that activate the editor. The editor is designer to be used as a 
singleton object where the smart getEditor function uses a closure to make sure to have it 
available.
    
Revision:
    2014/09/22  (HW, DAW)
        Initial version.
*/
export class DesObjectEditor{
constructor(oPrev){
    this.oObj = null;
    this.oPrev = oPrev;
}
/* 
Called by the designer to select the passed web object. It sets the oObj property.

@param  oObj    Web Object to be edited.
*/
select(oObj){
    this.oObj = oObj;
}

/* 
Called to clear the selected object.
*/
unselect(oNewSel){
    this.oObj = null;
}

/* 
Called by the designer on a resize to reposition the designer elements.
*/
reposition(){

}

/* 
Hook to implement key handlers.
*/
keypress(oEvent){

}

/* 
Standard dragging API which is used when objects are dragged from the class palette. This default 
implementation prevents the drop.

@param  bCreate     If true we are creating a new object as opposed to dragging an existing.
@return Object with drag & drop functions { end : ..., drop : ..., move : ... }
*/
initializeDrag(bCreate, oEv){
    function cancel(oEv){
        return false;
    }

    return {
        end : cancel,
        drop : cancel,
        move : cancel,
        hide : cancel
    };
}


}

/* 
The editor objects are added to the inheritance structure by adding a getEditor function to the 
class. That way objects inherit the editor of their superclass and can override the editor when 
needed. We use a closure to generate the getEditor function so that it can cache the editor object 
in a local variable.

@return Editor object.
*/
df.WebObject.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesObjectEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());