import { DesContainerEditor } from './WebAppDesignerContainerEditor.js';


df.acRegions = [
    "prCenter",
    "prLeft",
    "prRight",
    "prTop",
    "prBottom"
];

export class DesPanelEditor extends DesContainerEditor {
    
select(oObj){
    var eRegion;
    
    if(!this.eResizer){
        this.render(oObj);
    }
    
    eRegion = oObj.peRegion;
    this.eResizer.className = (eRegion === df.ciRegionLeft || eRegion === df.ciRegionRight ? 'WebPanel_DividerVertical' : 'WebPanel_DividerHorizontal') + " " + df.acRegions[eRegion];
    this.eResizer.style.display = (eRegion !== df.ciRegionCenter ? "" : "none");
    
    super.select(oObj);
    
}

unselect(oNewSel){
    super.unselect(oNewSel);
    
    if(this.eResizer){
        this.eResizer.style.width = "";
        this.eResizer.style.height = "";
        this.eResizer.style.marginTop = "";
        this.eResizer.style.marginLeft = "";
    }
}

render(oObj){
    super.render(oObj);
    
    this.eSelTop.appendChild(df.dom.create('<div class="prev_s_drag"></div>'));
    df.events.addDomListener("mousedown", this.eSelTop, this.onMove, this);
    
    
    //  Create divider if not there
    this.eResizer = df.dom.create('<div class=""></div>');
    this.eSel.appendChild(this.eResizer);
    
    df.events.addDomListener("mousedown", this.eResizer, this.onResize, this);    
}

position(oRect){
    var eRegion, iSize;
    
    super.position(...arguments);    
    eRegion = this.oObj.peRegion;
    if(oRect){
        if(eRegion === df.ciRegionLeft || eRegion === df.ciRegionRight){
            if(eRegion === df.ciRegionLeft){
                this.eResizer.style.left = (oRect.right - 8) + "px";
                this.eResizer.style.top = oRect.top + (oRect.height / 2) + "px";
            }else{  //  df.ciRegionRight
                this.eResizer.style.left = oRect.left + "px";
                this.eResizer.style.top = oRect.top + (oRect.height / 2) + "px";
            }
            
            
            
            if((oRect.height - 20) < this.eResizer.offsetHeight){
                iSize = Math.max(oRect.height - 20, 20);
                this.eResizer.style.height = iSize + "px";
                this.eResizer.style.marginTop = "-" + (Math.round(iSize / 2)) + "px";
            }
        }else{  //  Horizontal slider
            if(eRegion === df.ciRegionBottom){
                this.eResizer.style.top = oRect.top + "px";
                this.eResizer.style.left = oRect.left + (oRect.width / 2) + "px";
            }else{  //  df.ciRegionTop
                this.eResizer.style.top = (oRect.bottom - 8) + "px";
                this.eResizer.style.left = oRect.left + (oRect.width / 2) + "px";
            }
            
            if((oRect.width - 20) < this.eResizer.offsetWidth){
                iSize = Math.max(oRect.width - 20, 20);
                this.eResizer.style.width = iSize + "px";
                this.eResizer.style.marginLeft = "-" + (Math.round(iSize / 2)) + "px";
            }
        }
    }
}

initializeDrag(bCreate, oEv){
    var oObj, oPrnt, aDropElems = [], iDropElem = 0, oPrevContainer = this.oObj, iX, iY, oDropParent, eDropRegion, eDropElem, oRect;
    
   
    df.dom.addClass(document.body, "dragcursor");
    
    //  Determine current position
    if(!bCreate){
        oObj = this.oObj;
        oPrnt = this.oObj._oParent;
    }
    

    
    function renderDropElem(oContainer, eRegion, bCenter){
        var iTop, iLeft, iBox = 30, sClass = "paneldropzone";
        
        //  Create or reuse a drop element
        if(!aDropElems[iDropElem]){
            eDropElem = aDropElems[iDropElem] = df.dom.create('<div></div>');
            document.body.appendChild(eDropElem);
        }else{
            eDropElem = aDropElems[iDropElem];
        }
        iDropElem++;
        
        oRect = df.sys.gui.getBoundRect(oContainer.getPreviewerElem());
        
        //  Determine position
        iTop = oRect.top + (oRect.height / 2) - (iBox / 2);
        iLeft = oRect.left + (oRect.width / 2) - (iBox / 2);
        if(bCenter){
            sClass += " paneldropzone_first";
            switch (eRegion){
                case df.ciRegionTop:
                    iTop -= iBox; 
                    sClass += "top";
                    break;
                case df.ciRegionBottom:
                    iTop += iBox; 
                    sClass += "bottom";
                    break;
                case df.ciRegionLeft:
                    iLeft -= iBox;
                    sClass += "left";
                    break;
                case df.ciRegionRight:
                    iLeft += iBox;
                    sClass += "right";
                    break;
            }
        }else{
            sClass += " paneldropzone_deep";
            switch (eRegion){
                case df.ciRegionTop:
                    iTop = oRect.top;
                    sClass += "top";
                    break;
                case df.ciRegionBottom:
                    iTop = oRect.bottom - iBox;
                    sClass += "bottom";
                    break;
                case df.ciRegionLeft:
                    iLeft = oRect.left;
                    sClass += "left";
                    break;
                case df.ciRegionRight:
                    iLeft = oRect.right - iBox;
                    sClass += "right";
                    break;
            }
        }
        
        //  Position drop element
        eDropElem.style.left = iLeft + "px";
        eDropElem.style.top = iTop + "px";
        
        if(iX > iLeft && iX < (iLeft + iBox) && iY > iTop && iY < (iTop + iBox) && !oDropParent){
            sClass += " paneldropzone_selected";
            oDropParent = oContainer;
            eDropRegion = eRegion;
        }
        eDropElem.className = sClass;
    }
    
    //  
    //  Highlights the available drop options for a specific container.
    //
    function renderDropOptions(oContainer, iDepth){
        var bCenter = iDepth === 0 && !oContainer._bPanels;
    
        if(!oContainer._oRegionTop || oContainer._oRegionTop === oObj){
            renderDropElem(oContainer, df.ciRegionTop, bCenter);
        }
        if(!oContainer._oRegionLeft || oContainer._oRegionLeft === oObj){
            renderDropElem(oContainer, df.ciRegionLeft, bCenter);
        }
        if(!oContainer._oRegionCenter || oContainer._oRegionCenter === oObj){
            renderDropElem(oContainer, df.ciRegionCenter, bCenter);
        }
        if(!oContainer._oRegionRight || oContainer._oRegionRight === oObj){
            renderDropElem(oContainer, df.ciRegionRight, bCenter);
        }
        if(!oContainer._oRegionBottom || oContainer._oRegionBottom === oObj){
            renderDropElem(oContainer, df.ciRegionBottom, bCenter);
        }
    }
    
    function move(x, y){
        var eElem, oContainer = null, eDropElem, iDepth = 0;
        
        
        iX = x;
        iY = y;
        
        //  Determine if we are inside the current panel
        eElem = document.elementFromPoint(iX, iY);
        
        //  Find the container we are dragging into by inspecting the DOM
        while(eElem && eElem !== document && !(oContainer && oContainer._bIsContainer)){
            if(eElem.hasAttribute("data-dfobj")){
                oContainer = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
            }
            eElem = eElem.parentNode;
        }
        
        
        //  Use previous (or initial) container if none found which can happen if hovering a drop zone
        //  Also skip the webapp object if designing a view
        if(oContainer === null || (oContainer instanceof df.WebApp && this.oPrev._bHasView)){
            oContainer = oPrevContainer;
        }
        
        //  Reset globals
        oPrevContainer = oContainer;
        oDropParent = null;
        eDropRegion = 0;
        iDropElem = 0;
        
        //  Bubble up to highlight all the drop options
        while(oContainer){
            if(oContainer._bIsContainer && (oContainer._bPanels || oContainer._aUIObjects.length === 0) && oContainer !== oObj){
                renderDropOptions(oContainer, iDepth);
            }   
            
            iDepth++;
            
            if(oContainer instanceof df.WebBaseView){
                oContainer = null;
            }else{
                oContainer = oContainer._oParent;
            }
        }
        
        
        //  Remove drop elements that became unused
        while(aDropElems.length > iDropElem){
            eDropElem = aDropElems.pop();
            if(eDropElem.parentNode){
                eDropElem.parentNode.removeChild(eDropElem);
            }
        }
        
        return !!oDropParent;
        
    }
    
    
    function drop(sJsClassName){
        var sProps, oRect, iWidth = 0;
        
        if(oDropParent){
            if(oDropParent.piWidth > 0){ 
                iWidth = Math.max(Math.round(oDropParent.piWidth / 4), 25);
            }else{
                oRect = df.sys.gui.getBoundRect(oDropParent.getPreviewerElem());
                iWidth = Math.max(Math.round(oRect.width / 4), 25);
            }
        }
        
        if(bCreate){
            //  Determine properties to set on the dropped object
            sProps = "peRegion:" + df.acRegions[eDropRegion];   //  Set the region
            if(eDropRegion === df.ciRegionLeft || eDropRegion === df.ciRegionRight){    //  For left and right we also set an initial width
                sProps += ",piWidth:" + iWidth;
            }
            this.oPrev.studioDropObject(sJsClassName, oDropParent, null, sProps);
        }else{
            if(oDropParent){
                
                this.oPrev.studioStartTransaction();
                
                //  When moving to a left / right panel we make sure to set a width if not already available
                if(eDropRegion === df.ciRegionLeft || eDropRegion === df.ciRegionRight){
                    if(oObj.piWidth <= 0 || oObj.piWidth > iWidth){
                        this.oPrev.studioUpdateProp(oObj, "piWidth", iWidth);
                    }
                }else{  //  When moving away from a left / right panel position we make sure to clear the width if it was set
                    if(oObj.piWidth > 0){
                        this.oPrev.studioUpdateProp(oObj, "piWidth", "0");
                    }
                }
                
                //  When dropping as center, left or right panel we clear a height if it is was set..
                if(eDropRegion !== df.ciRegionTop && eDropRegion !== df.ciRegionBottom){
                    if(oObj.piHeight > 0){
                        this.oPrev.studioUpdateProp(oObj, "piHeight", "0");
                    }
                }
                
                this.oPrev.studioUpdateProp(oObj, "peRegion", df.acRegions[eDropRegion]);
                
                //  If we dropped somewhere else we move the object
                if(oDropParent !== oObj._oParent){
                    this.oPrev.studioMoveObject(oObj, oDropParent, null);
                }
                
                this.oPrev.studioEndTransaction();
            }
        }
    }
    
    function clear(){
        while(aDropElems.length > 0){
            eDropElem = aDropElems.pop();
            if(eDropElem.parentNode){
                eDropElem.parentNode.removeChild(eDropElem);
            }
        }
    }
    
    function end(){
        clear.call(this);
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    return {
        end : end,
        drop : drop,
        move : move,
        hide : clear
    };    
}

onResize(oEvent){
    var oObj = this.oObj, eRegion, eMask, iCurLeft, iStartLeft, iMin = 0, iMax = 0, iCurTop, iStartTop,
        iStartMouseY, iStartMouseX, oRect, eElem, iRightOffsetWidth, iBottomOffsetHeight, iDividerOffsetWidth, iDividerOffsetHeight;
    
    eRegion = oObj.peRegion;
    eMask = eMask = df.gui.dragMask();
    
    eElem = this.getPreviewerElem();
    oRect = df.sys.gui.getBoundRect(eElem);
    iRightOffsetWidth = this.eSelRight.offsetWidth;
    iBottomOffsetHeight = this.eSelBottom.offsetHeight;
    iDividerOffsetWidth = this.eResizer.offsetWidth;
    iDividerOffsetHeight = this.eResizer.offsetHeight;
    
    if(eRegion === df.ciRegionTop || eRegion === df.ciRegionBottom){  //  Horizontal
        eMask.style.cursor = "n-resize";
        
        //  Determine start position
        if(eRegion === df.ciRegionTop){
            iCurTop = oObj._eElem.clientHeight;
            
            iMin = (oObj.piMinHeight > 2 ? oObj.piMinHeight : 2);
            iMax = iCurTop + oObj._oParent._eMainArea.clientHeight;
            if(oObj._oParent._oRegionCenter && oObj._oParent._oRegionCenter.piMinHeight > 0){
                iMax = iMax - oObj._oParent._oRegionCenter.piMinHeight;
            }
        }else{  //  Bottom
            iCurTop = oObj._oParent._eMainArea.clientHeight;
            if(oObj._oParent._eRegionTop){
                iCurTop += oObj._oParent._eRegionTop.clientHeight;
                
                iMin = oObj._oParent._eRegionTop.clientHeight;
            }
            
            if(oObj._oParent._oRegionCenter && oObj._oParent._oRegionCenter.piMinHeight > 0){
                iMin += oObj._oParent._oRegionCenter.piMinHeight;
            }
            iMax = iCurTop + oObj._eElem.clientHeight - (oObj.piMinHeight > 0 ? oObj.piMinHeight : 0) - 10;
        }
    }else{ //   Vertical
        eMask.style.cursor = "e-resize";
        
        //  Determine start position
        if(eRegion === df.ciRegionLeft){
            iCurLeft = oObj._eElem.clientWidth;
            
            iMin = (oObj.piMinWidth > 2 ? oObj.piMinWidth : 2);
            
            iMax = iCurLeft + ((oObj._oParent._eRegionCenter && oObj._oParent._eRegionCenter.clientWidth) || oObj._oParent._eElem.clientWidth);
            if(oObj._oParent._oRegionCenter && oObj._oParent._oRegionCenter.piMinWidth > 0){
                iMax = iMax - oObj._oParent._oRegionCenter.piMinWidth;
            }else{
                iMax = iMax - 4;
            }
        }else{  //  Right
            iCurLeft = oObj._oParent._eMainArea.clientWidth - oObj._eElem.clientWidth;
            
             if(oObj._oParent._eRegionLeft){
                iMin = oObj._oParent._eRegionLeft.clientWidth;
            }
            
            if(oObj._oParent._oRegionCenter && oObj._oParent._oRegionCenter.piMinWidth > 0){
                iMin += oObj._oParent._oRegionCenter.piMinWidth;
            }
            iMax = iCurLeft + oObj._eElem.clientWidth - (oObj.piMinWidth > 0 ? oObj.piMinWidth : 0) - 10;
        }
    }
    
    iStartLeft = iCurLeft;
    iStartTop = iCurTop;
    iStartMouseX = oEvent.getMouseX();
    iStartMouseY = oEvent.getMouseY();
    
    function onResize(oEvent){
        var iLeft, iWidth, iHeight, iTop;
        
        if(eRegion === df.ciRegionTop || eRegion === df.ciRegionBottom){
            iCurTop = iStartTop - (iStartMouseY - oEvent.getMouseY());
            
            iCurTop = (iCurTop < iMax ? (iCurTop > iMin ? iCurTop : iMin) : iMax);
            
            if(eRegion === df.ciRegionTop){
                iHeight = iCurTop;
                
                iTop = (oRect.top + iHeight - iBottomOffsetHeight);//oRect.height  - (iStartTop - iCurTop) - iBottomOffsetHeight);
                this.eSelBottom.style.top = iTop + "px";
                this.eResizer.style.top = (iTop - iDividerOffsetHeight) + "px";
            }else if(eRegion === df.ciRegionBottom){
                iHeight = oObj._eElem.clientHeight + (iStartTop - iCurTop);
                
                iTop = (oRect.top - (iStartTop - iCurTop));
                this.eSelTop.style.top = iTop + "px";
                this.eSelLeft.style.top = iTop + "px";
                this.eSelRight.style.top = iTop + "px";
                
                this.eResizer.style.top = iTop + "px";
            }
                    
            this.eSelLeft.style.height = iHeight + "px";
            this.eSelRight.style.height = iHeight + "px";
            
        }else{
            iCurLeft = iStartLeft - (iStartMouseX - oEvent.getMouseX());
            iCurLeft = (iCurLeft < iMax ? (iCurLeft > iMin ? iCurLeft : iMin) : iMax);
            
            
            if(eRegion === df.ciRegionLeft){
                iWidth = iCurLeft;
                
                iLeft = (oRect.left + iWidth - iRightOffsetWidth);
                this.eSelRight.style.left = iLeft + "px";
                this.eResizer.style.left = (iLeft - iDividerOffsetWidth) + "px";
            }else{
                iWidth = oObj._eElem.clientWidth + (iStartLeft - iCurLeft);
                
                iLeft = oRect.left - (iStartLeft - iCurLeft);
                this.eSelLeft.style.left = iLeft + "px";
                this.eSelTop.style.left = iLeft + "px";
                this.eSelBottom.style.left = iLeft + "px";
                this.eResizer.style.left = iLeft + "px";
            }
            
            
            
            this.eSelTop.style.width = iWidth + "px";
            this.eSelBottom.style.width = iWidth + "px";
        }        
    }
    
    function onStopResize(oEvent){
        df.events.removeDomListener("mouseup", eMask, onStopResize, this);
        df.events.removeDomListener("mouseup", window, onStopResize, this);
        df.events.removeDomListener("mousemove", eMask, onResize, this);
    
        if(eMask && eMask.parentNode){
            eMask.parentNode.removeChild(eMask);
        }
        
        if(eRegion === df.ciRegionTop){
            oObj.piHeight = iCurTop;
            oObj._eElem.style.height = oObj.piHeight + "px";
            
            this.oPrev.studioUpdateProp(oObj, "piHeight", Math.round(oObj.piHeight));
        }else if(eRegion === df.ciRegionBottom){
            oObj.piHeight = oObj._eElem.clientHeight + (iStartTop - iCurTop);
            oObj._eElem.style.height = oObj.piHeight + "px";
            
            this.oPrev.studioUpdateProp(oObj, "piHeight", Math.round(oObj.piHeight));
        }else if(eRegion === df.ciRegionLeft){
            oObj.piWidth = iCurLeft;
            oObj._eElem.style.width = oObj.piWidth + "px";
            
            this.oPrev.studioUpdateProp(oObj, "piWidth", Math.round(oObj.piWidth));
        }else if(eRegion === df.ciRegionRight){
            oObj.piWidth = oObj._eElem.clientWidth + (iStartLeft - iCurLeft);
            oObj._eElem.style.width = oObj.piWidth + "px";
            
            this.oPrev.studioUpdateProp(oObj, "piWidth", Math.round(oObj.piWidth));
        }
        
        
        oObj.sizeChanged();
    }
    
    df.events.addDomListener("mousemove", eMask, onResize, this);
    df.events.addDomListener("mouseup", window, onStopResize, this);
    df.events.addDomListener("mouseup", eMask, onStopResize, this);
    
	oEvent.stop();
}



}


df.WebPanel.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesPanelEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());