import { DesUIObjectEditor } from './WebAppDesignerUIObjectEditor.js';

/* global df */

export class DesControlEditor extends DesUIObjectEditor {
select(oObj){
    super.select(oObj);
    
    if(!this.eSel){
        this.render(oObj);
    }
    
    this.reposition();
}

unselect(oNewSel){
    super.unselect(oNewSel);

    if(this.eSel){
        this.eSel.style.display = "none";
    }
}

render(oObj){
    var eSel;
    let aHtml = [];
    
    aHtml.push('<div class="preview_selected" style="display: none">');
    aHtml.push('    <div class="prev_s_top">');
    aHtml.push('        <div class="prev_s_movehoriz"></div>');
    aHtml.push('        <div class="prev_s_resizehoriz"></div>');
    aHtml.push('        <div class="prev_s_drag"></div>');
    aHtml.push('    </div>');
    aHtml.push('    <div class="prev_s_right"></div>');
    aHtml.push('    <div class="prev_s_left"></div>');
    aHtml.push('    <div class="prev_s_bottom"></div>');
    aHtml.push('    <div class="prev_s_gridresizehandle"></div>');
    aHtml.push('</div>');
    
    this.eSel = eSel = df.dom.create(aHtml.join(''));
    
    this.eSelTop = df.dom.query(eSel, 'div.prev_s_top');
    this.eSelLeft = df.dom.query(eSel, 'div.prev_s_left');
    this.eSelBottom = df.dom.query(eSel, 'div.prev_s_bottom');
    this.eSelRight = df.dom.query(eSel, 'div.prev_s_right');
    this.eResHoriz = df.dom.query(eSel, 'div.prev_s_resizehoriz');
    this.eMoveHoriz = df.dom.query(eSel, 'div.prev_s_movehoriz');
    this.eDragMove = df.dom.query(eSel, 'div.prev_s_drag');
    this.eGridResizeHandle = df.dom.query(eSel, 'div.prev_s_gridresizehandle');
    
    df.events.addDomListener("mousedown", this.eResHoriz, this.onResizeHoriz, this);
    df.events.addDomListener("mousedown", this.eMoveHoriz, this.onMoveHoriz, this);
    df.events.addDomListener("mousedown", this.eSelTop, this.onMove, this);
    df.events.addDomListener("mousedown", this.eGridResizeHandle, this.onGridControlResize, this);
    
    // Todo: Show hide handles based on Grid or Flow container
    
    this.oPrev._eRenderTo.parentNode.appendChild(eSel);
}


position(oRect){
    super.position(...arguments);
    
    this.eMoveHoriz.style.display = (oRect.width > this.eResHoriz.offsetWidth * 2 ? "" : "none");
    this.eDragMove.style.display = (oRect.width > this.eResHoriz.offsetWidth * 3 ? "" : "none");

    if (this.eGridResizeHandle) {
        this.eGridResizeHandle.style.top = (Math.round(oRect.top) + Math.round(oRect.height) - this.eGridResizeHandle.offsetHeight) + "px";
        this.eGridResizeHandle.style.left = (Math.round(oRect.left) + Math.round(oRect.width) - this.eGridResizeHandle.offsetWidth - 5) + "px";
    }

    // Show / hide handles based on flow or grid container
    let eElem = this.oObj.getPreviewerElem();
    let oObjParentContainer = this.getParentContainer(eElem);

    if (oObjParentContainer && oObjParentContainer.isGridLayout()) {
        this.eGridResizeHandle.style.display = 'block';
        this.eResHoriz.style.display = 'none';
        this.eMoveHoriz.style.display = 'none';
    } else {
        this.eGridResizeHandle.style.display = 'none';
        this.eResHoriz.style.display = 'block';
        this.eMoveHoriz.style.display = 'block';
    }
}

getParentContainer(eStartElem) {
    let oObjParentContainer;
    let eElem = eStartElem;

    while(eElem && eElem !== document && (!(oObjParentContainer && oObjParentContainer._bIsContainer) || (oObjParentContainer == this.oObj))){
        if(eElem.hasAttribute("data-dfobj")){
            oObjParentContainer = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
        }
        eElem = eElem.parentNode;
    }

    return oObjParentContainer;
}

onGridControlResize(oEv) {
    var eElem, iNewColSpan, iNewRowSpan, eMask, oObjParentContainer, oTmpEditor, oObj = this.oObj;
    var aCells = [], eCell;

    eElem = oObj.getPreviewerElem();
    oObjParentContainer = this.getParentContainer(eElem);

    if (oObjParentContainer && !oObjParentContainer.isGridLayout()) { return false; }

    oTmpEditor = oObjParentContainer.getEditor(this.oPrev, true);
    oTmpEditor._oContainer = oObjParentContainer;

    // Select parent to show grid
    if (!oTmpEditor._eGridOverLay) {
        if (!oTmpEditor.drawGridOverLay(oObjParentContainer)) { 
            return false; 
        }
    } 
    oTmpEditor.showGrid(); 
    

    const aPointElems  = document.elementsFromPoint(oEv.getMouseX(), oEv.getMouseY());
    for (let e=0; e < aPointElems.length; e++) {
        if (aPointElems[e].classList.contains("prev_s_gridoverlay_cell") ) {
            eCell = aPointElems[e];
            break;
        }
    }

    let iStartRowIndex, iStartColIndex;
    if(eCell){
        iStartRowIndex = determineRow(oObj, eCell);
        iStartColIndex = determineColumn(oObj, eCell);
    }else{
        iStartRowIndex = (oObj.piRowIndex > -1) ? oObj.piRowIndex : 0;
        iStartColIndex = (oObj.piColumnIndex > -1) ? oObj.piColumnIndex : 0;
    }

    this.bAutoRepos = false;

    eMask = oTmpEditor._eGridOverLay;
    if (!eMask) { return; }
    eMask.style.cursor = "nwse-resize";  

    function onResize(oEv) {
        let ePointElem;
            
        let iX = oEv.getMouseX();
        let iY = oEv.getMouseY();

        ePointElem  = document.elementFromPoint(iX, iY);

        if (!ePointElem || !ePointElem.classList.contains("prev_s_gridoverlay_cell")) { 
            return false; 
        }
        
        // Clear cell highlighting
        for (let iCell = 0; iCell < aCells.length; iCell++) {
            if (aCells[iCell]) {
                aCells[iCell].style.backgroundColor = 'transparent';
            }
        }

        aCells = [];

        // Highlight cells
        eCell = ePointElem;
        let sCellID = eCell.dataset.dfcellid;
        let iRow = (parseInt(sCellID.split('-')[0]));
        let iCol = (parseInt(sCellID.split('-')[1]));
        iNewRowSpan = iRow - iStartRowIndex + 1;
        iNewColSpan = iCol - iStartColIndex + 1;

        for (let r = iStartRowIndex; r <= iRow; r++) {
            for (let c = iStartColIndex; c <= iCol; c++) {
                let eTmpCell = (df.dom.query(oTmpEditor._eGridOverLay, '[data-dfcellid="'+r+'-'+c+'"]'));
                if (eTmpCell) {
                    eTmpCell.style.backgroundColor = 'rgba(84, 175, 255, 0.5)';
                    aCells.push(eTmpCell);
                }
            }
        }
    }

    function onStopResize(oEv){
        df.events.removeDomListener("mouseup", eMask, onStopResize, this);
        df.events.removeDomListener("mouseup", window, onStopResize, this);
        df.events.removeDomListener("mousemove", eMask, onResize, this);
        
        let bColChanged = (iNewColSpan && (oObj.piColumnSpan !== iNewColSpan));
        let bRowChanged = (iNewRowSpan && (oObj.piRowSpan !== iNewRowSpan));

        if(bColChanged || bRowChanged){
            this.oPrev.studioStartTransaction();
            if (bColChanged) {
                this.oPrev.studioUpdateProp(oObj, "piColumnSpan", iNewColSpan);
            }
            if (bRowChanged) {
                this.oPrev.studioUpdateProp(oObj, "piRowSpan", iNewRowSpan);
            }
            this.oPrev.studioEndTransaction();
        }else{
            this.reposition();
        }

        if (oTmpEditor) {
            oTmpEditor.destroyGrid();
        }

        this.bAutoRepos = true;
    }

    function determineRow(oObj, eCell) {
        let iRowSpan = 1;

        if (oObj.piRowIndex > -1) { 
            return oObj.piRowIndex;
        }

        let sCellID = eCell.dataset.dfcellid;
        let iCellRow = (parseInt(sCellID.split('-')[0]));
        
        if (oObj.piRowSpan <= 0) {
            iRowSpan = 1;
        } else {
            iRowSpan = oObj.piRowSpan;
        }

        let iStartRow = iCellRow - (iRowSpan - 1);

        return iStartRow;
    }

    function determineColumn(oObj, eCell) {
        let iColSpan = 1;

        if (oObj.piColumnIndex > -1) { 
            return oObj.piColumnIndex;
        }

        let sCellID = eCell.dataset.dfcellid;
        let iCellCol = (parseInt(sCellID.split('-')[1]));

        if (oObj.piColumnSpan <= 0) {
            iColSpan = 1;
        } else {
            iColSpan = oObj.piColumnSpan;
        }

        let iStartCol = iCellCol - (iColSpan - 1);

        return iStartCol;
    }

    df.events.addDomListener("mousemove", eMask, onResize, this);
    df.events.addDomListener("mouseup", window, onStopResize, this);
    df.events.addDomListener("mouseup", eMask, onStopResize, this);
        
    oEv.stop();
}

onResizeHoriz(oEv){
    var eMask, eRuler, eElem, oRect, iStartWidth, iStartSpan, iStartMouseX, iStepWidth, iMaxSpan, iRightOffsetWidth, iSpan, iWidth, iPrevSpan, oObj = this.oObj;
    
    this.bAutoRepos = false;

    if(oObj._oParent && oObj._oParent._bIsContainer){
        eRuler = this.oPrev.renderRuler(oObj._oParent);
        this.oPrev._eRenderTo.appendChild(eRuler);
    }
    
    eMask = df.gui.dragMask();
    eMask.style.cursor = "e-resize";
    
    eElem = oObj.getPreviewerElem();
    oRect = df.sys.gui.getBoundRect(eElem);
    
    iStartMouseX = oEv.getMouseX();
    iMaxSpan = oObj._oParent.piColumnCount - oObj.piColumnIndex;
    iSpan = iPrevSpan = iStartSpan = (oObj.piColumnSpan > 0 && oObj.piColumnSpan < iMaxSpan ? oObj.piColumnSpan : iMaxSpan);
    iStartWidth = oRect.width;
    iStepWidth = iStartWidth / iStartSpan;
    
    iRightOffsetWidth = this.eSelRight.offsetWidth;
    
    function onResize(oEv){
        var iStepChange, iOffset; 
        
        iOffset = oEv.getMouseX() - iStartMouseX;
        iStepChange = iOffset / iStepWidth;
        iSpan = Math.round(iStartSpan + iStepChange);
        
        if(iSpan < 1){
            iSpan = 1;
        }else if(iSpan > iMaxSpan){
            iSpan = iMaxSpan;
        }
        
        if(iSpan !== iPrevSpan){
            iWidth = iSpan * iStepWidth;
        
            this.eSelTop.style.width = iWidth + "px";
            this.eSelBottom.style.width = iWidth + "px";
            this.eSelRight.style.left = (oRect.left + iWidth - iRightOffsetWidth) + "px";
        
            iPrevSpan = iSpan;
        }
    }
    
    function onStopResize(oEv){
        df.events.removeDomListener("mouseup", eMask, onStopResize, this);
        df.events.removeDomListener("mouseup", window, onStopResize, this);
        df.events.removeDomListener("mousemove", eMask, onResize, this);
        
        if(eMask && eMask.parentNode){
            eMask.parentNode.removeChild(eMask);
        }
        
        if(eRuler && eRuler.parentNode){
            eRuler.parentNode.removeChild(eRuler);
        }
        
        if(oObj.piColumnSpan !== iSpan){
            this.oPrev.studioUpdateProp(oObj, "piColumnSpan", iSpan);
        }else{
            this.reposition();
        }


        this.bAutoRepos = true;
    }
    
    df.events.addDomListener("mousemove", eMask, onResize, this);
    df.events.addDomListener("mouseup", window, onStopResize, this);
    df.events.addDomListener("mouseup", eMask, onStopResize, this);
        
    oEv.stop();
}

onMoveHoriz(oEv){
    var eMask, eElem, eRuler, oRect, iStartWidth, iStartIndex, iStartMouseX, iStepWidth, iMaxIndex, iRightOffsetWidth, iIndex, iLeft, iPrevIndex, oObj = this.oObj, iMaxSpan, iSpan;
    
    this.bAutoRepos = false;

    //  Create mask
    eMask = df.gui.dragMask();
    eMask.style.cursor = "e-resize";
    
    //  Render ruler
    if(oObj._oParent && oObj._oParent._bIsContainer){
        eRuler = this.oPrev.renderRuler(oObj._oParent);
        this.oPrev._eRenderTo.appendChild(eRuler);
        }
    
    //  Determine current position
    eElem = oObj.getPreviewerElem();
    oRect = df.sys.gui.getBoundRect(eElem);
    
    //  Calculate initials
    iStartMouseX = oEv.getMouseX();
    iStartWidth = oRect.width;
    iIndex = iPrevIndex = iStartIndex = Math.max(oObj.piColumnIndex, 0);
    
    iMaxSpan = oObj._oParent.piColumnCount - oObj.piColumnIndex;
    iSpan = (oObj.piColumnSpan > 0 && oObj.piColumnSpan < iMaxSpan ? oObj.piColumnSpan : iMaxSpan);
    
    iStepWidth = iStartWidth / iSpan;
    iMaxIndex = oObj._oParent.piColumnCount - iSpan;
    
    iRightOffsetWidth = this.eSelRight.offsetWidth;
    
    function onResize(oEv){
        var iStepChange, iOffset;
        
        //  Determine new index based on mouse position
        iOffset = oEv.getMouseX() - iStartMouseX;
        iStepChange = iOffset / iStepWidth;
        iIndex = Math.round(iStartIndex + iStepChange);
        
        if(iIndex < 0){
            iIndex = 0;
        }else if(iIndex > iMaxIndex){
            iIndex = iMaxIndex;
        }
        
        //  Update designer element based on new index
        if(iIndex !== iPrevIndex){
            //oObj.set("piColumnIndex", iIndex);
            iPrevIndex = iIndex;
            
            iLeft = oRect.left + ((iIndex - iStartIndex) * iStepWidth);
            
            this.eSelLeft.style.left = iLeft + "px";
            this.eSelTop.style.left = iLeft + "px";
            this.eSelBottom.style.left = iLeft + "px";
           
            this.eSelRight.style.left = (iLeft + oRect.width - iRightOffsetWidth) + "px";
        }
    }
    
    function onStopResize(oEv){
        //  Clean up
        df.events.removeDomListener("mouseup", eMask, onStopResize, this);
        df.events.removeDomListener("mouseup", window, onStopResize, this);
        df.events.removeDomListener("mousemove", eMask, onResize, this);

        if(eMask && eMask.parentNode){
            eMask.parentNode.removeChild(eMask);
        }
        
        if(eRuler && eRuler.parentNode){
            eRuler.parentNode.removeChild(eRuler);
        }
        
        if(oObj.piColumnIndex !== iIndex){
            this.oPrev.studioStartTransaction();
            
            //  Tell studio about the change
            this.oPrev.studioUpdateProp(oObj, "piColumnIndex", iIndex);
            
            //  Update the column span if it was set to max-width to match the shown size
            if(oObj.piColumnSpan === 0 && iIndex < oObj.piColumnIndex){    
                this.oPrev.studioUpdateProp(oObj, "piColumnSpan", iSpan);
            }
            
            this.oPrev.studioEndTransaction();
            //  Update the actual index
            // oObj.set("piColumnIndex", iIndex);
        }else{
            this.reposition();
        }
        this.bAutoRepos = true;
    }
    
    df.events.addDomListener("mousemove", eMask, onResize, this);
    df.events.addDomListener("mouseup", window, onStopResize, this);
    df.events.addDomListener("mouseup", eMask, onStopResize, this);
        
    oEv.stop();
}

initializeDrag(bCreate, oEv){
    var eMarker, oStartPrnt, iLastX = -1, iLastY, iStartX, iStartY, oPrnt = null, oStartNext  = null, oNext = null, oObj = this.oObj, iChild;
    var eCell = null, aCells = [], iRow = -1, iCol = -1, iRowSpan = 1, iColSpan = 1;
    var oCurObj = null;
    
    eMarker = df.dom.create('<div class="preview_insertmark"></div>');
    document.body.appendChild(eMarker);
    
    df.dom.addClass(document.body, "dragcursor");
    
    //  Determine current position
    if(!bCreate){
        oStartPrnt = oPrnt = oObj._oParent;
        
        iChild = oPrnt._aUIObjects.indexOf(oObj);
        if(iChild < oPrnt._aUIObjects.length - 1){
            oStartNext = oNext = oPrnt._aUIObjects[iChild + 1];
        }
    }

    iColSpan = (bCreate ? 1 : (oObj.piColumnSpan > 0 ? oObj.piColumnSpan : 1) );
    iRowSpan = (bCreate ? 1 : (oObj.piRowSpan > 0 ? oObj.piRowSpan : 1) );
    let iColSpanOffset = (bCreate ? 0 : Math.floor(oObj.piColumnSpan / 2));

    iStartX = oEv?.getMouseX() || null;
    iStartY = oEv?.getMouseY() || null;

    // function inside(x, y, oRect){
        // return (y > oRect.top && y < oRect.bottom && x > oRect.left && x < oRect.right);
    // }

    function move(iX, iY){
        var i, oCurRect, iTop, iHeight, bBefore = false, eElem, oNewPrnt = null, oTestPrnt, oTmpEditor;
        
        if (iX == iStartX && iY == iStartY) {
            return true;
        }

        if(iLastX < 0){
            iLastX = iX;
            iLastY = iY;
        }
        
        let aElems = document.elementsFromPoint(iX, iY);
        let iEl = 0;
        let eOverlay = null;

        while(iEl < aElems.length && !(oNewPrnt && oNewPrnt._bIsContainer)){
            eElem = aElems[iEl];
            if(eElem.hasAttribute("data-dfcontainerobj")){
                eOverlay = eElem;
            } else if(eElem.hasAttribute("data-dfobj")){
                oNewPrnt = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
            }

            iEl ++
        }

        if (!(oNewPrnt && oNewPrnt._bIsContainer)) {
            if (eOverlay) {
                oNewPrnt = this.oPrev.findObj(eOverlay.getAttribute("data-dfcontainerobj"));
            } else if (oObj){
                // Go with the parent method (sometimes the handle is outside the webview, which means there is no container under the cursor, this fixes that case)
                let oTmpParent = oObj?._oParent;
                while (!(oTmpParent._bIsContainer || oTmpParent instanceof df.WebBaseView)) {
                    oTmpParent = oTmpParent._oParent;
                }

                oNewPrnt = oTmpParent;
            }            
        }

        if (oCurObj && oCurObj != oNewPrnt && oCurObj.isGridLayout()) {
            oTmpEditor = oCurObj.getEditor(this.oPrev, true);
            oTmpEditor.destroyGrid();
        }

        //  Check if we are not dragging into the selected control itself (unless creating a new object)
        oTestPrnt = oNewPrnt;
        while(!bCreate && oTestPrnt){
            if(oTestPrnt === oObj){
                oNewPrnt = oObj._oParent;
            }
            
            oTestPrnt = oTestPrnt._oParent;
        }
        
        //  Check if we are hovering outside the view
        if(!oPrnt && !oNewPrnt && this.oPrev._bHasView){
            oNewPrnt = this.oPrev._aViews[0] || null;
        }
        if(!oPrnt && oNewPrnt instanceof df.WebBaseView){
            while(oNewPrnt && oNewPrnt._bPanels){
                oNewPrnt = oNewPrnt._oRegionCenter;
            }
        }

        oCurObj = oNewPrnt;
        
        if(oNewPrnt && oNewPrnt._bIsContainer && !oNewPrnt._bPanels){
            oPrnt = oNewPrnt;
            i = 0;
            
            // Grid logic, highlight cell
            if(oPrnt.isGridLayout()) {
                oTmpEditor = oPrnt.getEditor(this.oPrev, true);
                // Select parent to show grid
                if (!oTmpEditor._eGridOverLay) {
                    if(!oTmpEditor.drawGridOverLay(oPrnt)){ return };   
                    oTmpEditor.positionGridOverlay(oPrnt);
                } else {
                    oTmpEditor.showGrid(oPrnt);
                }

                // Find td
                let ePointElem = document.elementFromPoint(iX, iY);
                if (!ePointElem.classList.contains("prev_s_gridoverlay_cell")) { return false; }

                for (let iCell = 0; iCell < aCells.length; iCell++) {
                    if (aCells[iCell]) {
                        aCells[iCell].style.backgroundColor = 'transparent';
                    }
                }

                aCells = [];

                eCell = ePointElem;
                let sCellID = eCell.dataset.dfcellid;
                iRow = (parseInt(sCellID.split('-')[0]));

                iCol = (parseInt(sCellID.split('-')[1]));
                iCol -= Math.min(iColSpanOffset, iCol);

                let toRow = iRow + iRowSpan - 1;
                let toCol = iCol + iColSpan - 1;

                for (let r = iRow; r <= toRow; r++) {
                    for (let c = iCol; c <= toCol; c++) {
                        let eTmpCell = (df.dom.query(oTmpEditor._eGridOverLay, '[data-dfcellid="'+r+'-'+c+'"]'));
                        if (eTmpCell) {
                            eTmpCell.style.backgroundColor = 'rgba(84, 175, 255, 0.5)';
                            aCells.push(eTmpCell);
                        }
                    }
                }
            }

            // Flow logic
            //  Find control to insert after
            if(oPrnt._aUIObjects.length > 0){
            
                //  Find the first control that starts below the cursor
                oCurRect = df.sys.gui.getBoundRect(oPrnt._aUIObjects[i].getPreviewerElem());
                while((!oCurRect.top || oCurRect.top < iY) && i < oPrnt._aUIObjects.length - 1){
                    i++;
                    oCurRect = df.sys.gui.getBoundRect(oPrnt._aUIObjects[i].getPreviewerElem());
                }
                
                //  Go up until we found the first control that starts to the left and above the cursor
                if(i > 0 && (oCurRect.top > iY || oCurRect.left > iX)){
                    i--;
                    oCurRect = df.sys.gui.getBoundRect(oPrnt._aUIObjects[i].getPreviewerElem());
                    

                    while((!oCurRect.top || oCurRect.left > iX) && i > 0){
                         i--;
                        oCurRect = df.sys.gui.getBoundRect(oPrnt._aUIObjects[i].getPreviewerElem());
                    }
                }
                
                //  Special logic to allow insertion as the first item
                if((i === 0 && iY < oCurRect.top) || iX < oCurRect.left){
                    bBefore = true;
                }else{
                    bBefore = (iX - oCurRect.left < oCurRect.width * 0.4);
                }                
            }
            
            //  Determine next for studio
            if(oPrnt._aUIObjects[i]){
                if(bBefore){
                    oNext = oPrnt._aUIObjects[i];
                }else{
                    oNext = (i < oPrnt._aUIObjects.length - 1 && oPrnt._aUIObjects[i + 1]) || null;
                }
            }else{
                oNext = null;
                
                oCurRect = df.sys.gui.getBoundRect(oPrnt.getInsertionObject());
                bBefore = true;
            }
            
            if(oPrnt.isFlowLayout()) {
                //  Position marker
                iTop = oCurRect.top;
                iHeight = oCurRect.height;
                
                if(iHeight < 20){
                    iTop = iTop - (10 - iHeight / 2);
                    iHeight = 20;
                }
                
                eMarker.style.display = "";
                eMarker.style.top = iTop + "px";
                eMarker.style.height =  iHeight + "px";
                
                if(bBefore){
                    eMarker.style.left = oCurRect.left + "px";
                }else{
                    eMarker.style.left = oCurRect.right + "px";
                }
            }

            return true;
        }
        
        return false;
    }
    
    function hide(){
        if (oCurObj && oCurObj.isGridLayout()) {
            const oTmpEditor = oCurObj.getEditor(this.oPrev, true);
            oTmpEditor.destroyGrid();
        }

        eMarker.style.display = "none";
    }
    
    function end(){
        if(eMarker && eMarker.parentNode){
            eMarker.parentNode.removeChild(eMarker);
        }

        for (let iCell = 0; iCell < aCells.length; iCell++) {
            if (aCells[iCell]) {
                aCells[iCell].style.backgroundColor = 'transparent';
            }
        }

        aCells = [];
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    function drop(sJsClassName){
        if(bCreate){
            if (oPrnt.isGridLayout()) {
                this.oPrev.studioDropObject(sJsClassName, oPrnt, oNext, ("piRowIndex:" + iRow + ",piColumnIndex:" + iCol));
            } else {
                this.oPrev.studioDropObject(sJsClassName, oPrnt, oNext, "");
            }
        }else{
            this.oPrev.studioStartTransaction();

            // Grid clause
            if (oPrnt.isGridLayout()) {
                if (iRow !== undefined && iRow >= 0) {
                    this.oPrev.studioUpdateProp(oObj, "piRowIndex", iRow);
                }
                if (iCol !== undefined && iCol >= 0) {
                    this.oPrev.studioUpdateProp(oObj, "piColumnIndex", iCol);
                }
            }

            if(oNext !== oObj && (oStartPrnt !== oPrnt || oStartNext !== oNext)){
                this.oPrev.studioMoveObject(oObj, oPrnt, oNext);
            }            

            this.oPrev.studioEndTransaction();
        }

        if (oCurObj) {
            let oTmpEditor = oCurObj.getEditor(this.oPrev, true);
            oTmpEditor.destroyGrid();
        }
    }
    
    return {
        end : end,
        drop : drop,
        move : move,
        hide : hide
    };
        
}

keypress(oEvent){
    var oObj = this.oObj, iIndex;
    
    if(oObj){
        //  Move left and right by changing column index
        if(oEvent.matchKey(df.settings.designerKeys.moveLeft)){
            if(oObj.piColumnIndex > 0){
                oObj.set("piColumnIndex", oObj.piColumnIndex - 1);
                this.oPrev.studioUpdateProp(oObj, "piColumnIndex", oObj.piColumnIndex);
                
                oEvent.stop();
            }
        }
        if(oEvent.matchKey(df.settings.designerKeys.moveRight)){
            if((oObj.piColumnIndex + oObj.piColumnSpan) < oObj._oParent.piColumnCount){
                oObj.set("piColumnIndex", oObj.piColumnIndex + 1);
                this.oPrev.studioUpdateProp(oObj, "piColumnIndex", oObj.piColumnIndex);
                
                oEvent.stop();
            }
        }
        
        //  Grow & shrink horizontally by changing the column span
        if(oEvent.matchKey(df.settings.designerKeys.growHoriz)){
            if((oObj.piColumnIndex + oObj.piColumnSpan) < oObj._oParent.piColumnCount && oObj.piColumnSpan !== 0){
                oObj.set("piColumnSpan", oObj.piColumnSpan + 1);
                this.oPrev.studioUpdateProp(oObj, "piColumnSpan", oObj.piColumnSpan);
                
                oEvent.stop();
            }
        }
        if(oEvent.matchKey(df.settings.designerKeys.shrinkHoriz)){
            if(oObj.piColumnSpan > 1){
                oObj.set("piColumnSpan", oObj.piColumnSpan - 1);
                this.oPrev.studioUpdateProp(oObj, "piColumnSpan", oObj.piColumnSpan);
                
                oEvent.stop();
            }else if(oObj.piColumnSpan === 0){
                oObj.set("piColumnSpan", oObj._oParent.piColumnCount - oObj.piColumnIndex - 1);
                this.oPrev.studioUpdateProp(oObj, "piColumnSpan", oObj.piColumnSpan);
                
                oEvent.stop();
            }
        }
        
        //  Move up and down by moving objects
        if(oEvent.matchKey(df.settings.designerKeys.moveUp)){
            iIndex = oObj._oParent._aUIObjects.indexOf(oObj);
            if(iIndex > 0){
                this.oPrev.studioMoveObject(oObj, oObj._oParent, oObj._oParent._aUIObjects[iIndex - 1]);
            
                oEvent.stop();
            }
        }
        if(oEvent.matchKey(df.settings.designerKeys.moveDown)){
            iIndex = oObj._oParent._aUIObjects.indexOf(oObj);
            if(iIndex < oObj._oParent._aUIObjects.length - 1){
                this.oPrev.studioMoveObject(oObj, oObj._oParent, oObj._oParent._aUIObjects[iIndex + 2]);
            
                oEvent.stop();
            }
        }
    }
}


}


df.WebBaseControl.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev){    
        if(!oEditor){
            oEditor = new DesControlEditor(oPrev);
        }
        
        if(this._bIsWO){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());