import { DesContainerEditor } from './WebAppDesignerContainerEditor.js';

export class DesTabPageEditor extends DesContainerEditor {

constructor(oPrev) {
    super(oPrev);

    this.sSelectorClassName = "preview_selected_tabpage";
}

unselect(oNewSel){
    super.unselect(oNewSel);
    
    if(this.eBtnSel){
        this.eBtnSel.style.display = "none";
    }
}

render(oObj){
    var eBtnSel;
    
    super.render( oObj);
    
    this.eBtnSel = eBtnSel = df.dom.create('<div class="preview_selected"><div class="prev_s_top"></div><div class="prev_s_right"></div><div class="prev_s_left"></div></div>');
    
    this.eBtnSelTop = df.dom.query(eBtnSel, 'div.prev_s_top');
    this.eBtnSelLeft = df.dom.query(eBtnSel, 'div.prev_s_left');
    this.eBtnSelRight = df.dom.query(eBtnSel, 'div.prev_s_right');
    
    this.oPrev._eRenderTo.parentNode.appendChild(this.eBtnSel);
    
    this.eSelTopLeft = df.dom.create('<div class="prev_tab_top"></div>');
    this.eSelTopRight = df.dom.create('<div class="prev_tab_top"></div>');
    this.eSel.appendChild(this.eSelTopLeft);
    this.eSel.appendChild(this.eSelTopRight);
    
    this.eDragMove = df.dom.create('<div class="prev_s_drag"></div>');
    // this.eSelTop.insertBefore(this.eDragMove, this.eIncrCol);
    this.eBtnSelTop.appendChild(this.eDragMove);
    
    df.events.addDomListener("mousedown", this.eBtnSel, this.onMove, this);
}


reposition(){
    var eElem, oRectCont = null, oRect = null;
    
    if(this.eSel && this.oObj){
        
        eElem = this.getPreviewerElem();
        
        if(eElem && this.oObj._bShown && df.sys.gui.isOnScreen(eElem)){
            oRectCont = df.sys.gui.getBoundRect(eElem);
        }
        
        //  Position the tab selector
        if(this.oObj._eBtn && this.oObj._oParent._bShown && df.sys.gui.isOnScreen(this.oObj._eBtn)){
            this.eBtnSel.style.display = "";
            
            oRect = df.sys.gui.getBoundRect(this.oObj._eBtn);
                    
            this.eBtnSelTop.style.top = Math.round(oRect.top) + "px";
            this.eBtnSelTop.style.left = Math.round(oRect.left) + "px";
            this.eBtnSelTop.style.width = Math.round(oRect.width) + "px";
            
            this.eBtnSelLeft.style.top = Math.round(oRect.top) + "px";
            this.eBtnSelLeft.style.left = Math.round(oRect.left) + "px";
            this.eBtnSelLeft.style.height = Math.round((oRectCont && oRectCont.top - oRect.top) || oRect.height) + "px";
            
            this.eBtnSelRight.style.top = Math.round(oRect.top) + "px";
            this.eBtnSelRight.style.left = (Math.round(oRect.left) + Math.round(oRect.width)- this.eSelRight.offsetWidth) + "px";
            this.eBtnSelRight.style.height = Math.round((oRectCont && oRectCont.top - oRect.top) || oRect.height) + "px";
        }else{
            this.eBtnSel.style.display = "none";
        }
        
        
        
        if(this._eRuler && this._eRuler.parentNode){
            this._eRuler.parentNode.removeChild(this._eRuler);
        }
        
        if(oRectCont){
            this.eSelTopLeft.style.top = Math.round(oRectCont.top) + "px";
            this.eSelTopLeft.style.left = Math.round(oRectCont.left) + "px";
            
            if(oRect){
                this.eSelTopLeft.style.width = Math.round(oRect.left - oRectCont.left + this.eBtnSelLeft.offsetWidth) + "px";
                this.eSelTopRight.style.left = Math.round(oRect.right - this.eBtnSelRight.offsetWidth) + "px";
                this.eSelTopRight.style.width = Math.round(oRectCont.right - oRect.right + this.eBtnSelRight.offsetWidth) + "px";
            }
            
            this.eSelTopRight.style.top = Math.round(oRectCont.top) + "px";
            
            this.position(df.sys.gui.getBoundRect(eElem));
        }else{
            this.eSel.style.display = "none";
        }
    }
}


initializeDrag(bCreate, oEv){
    var eMarker, oCardCon, oNextCard = null, oStartCardCon, oStartNextCard, oObj = this.oObj, i, iInitialY = 0;
    
    eMarker = df.dom.create('<div class="preview_insertmark"></div>');
    document.body.appendChild(eMarker);
    
    df.dom.addClass(document.body, "dragcursor");
    
    //  If dragging an existing tab we determine the initial values (CardCon, next sibbling and before)
    if(!bCreate){
        oStartCardCon = oObj._oParent;
        
        for(i = 0; i < oStartCardCon._aCards.length; i++){
            if(oStartCardCon._aCards[i] === oObj){
                if(i + 1 <  oStartCardCon._aCards.length){
                    oNextCard = oStartCardCon._aCards[i + 1];
                }
                
                break;
            }
        }
    }
    
    function hide(){
        oCardCon = null;
        oNextCard = null;
        eMarker.style.display = "none";
    }
    
    function move(iX, iY){
        var oRect, eElem, oHover = null, oCard, bBefore = false, eTabBtn, eInsertElem, i, iAttempt = 2;
        
        //  Remember initial Y position
        if(!iInitialY){
            iInitialY = iY;
        }
        
        //  Find the tab button and control
        eElem = document.elementFromPoint(iX, iY);
        while(iAttempt > 0 && !eTabBtn){
            while(eElem && eElem !== document && !(oHover)){
                if(eElem === eMarker || eElem === this.eBtnSelLeft || eElem === this.eBtnSelRight){
                    return;
                }
                if(eElem.className.indexOf("WebTab_Btn") >= 0){
                    eTabBtn = eElem;
                }
                
                if(eElem.hasAttribute("data-dfobj")){
                    oHover  = this.oPrev.findObj(eElem.getAttribute("data-dfobj"));
                }
                eElem = eElem.parentNode;
            }
            
            //  Retry when dragging an existing tab and we are the same height as we started and look 25 pixels down, this increases the button hover area untill roughly arround the bar above the tab being dragged
            if(!bCreate && !eTabBtn && iAttempt === 2 && Math.abs(iInitialY - iY) < 20){
                eElem = document.elementFromPoint(iX, iY + 25);
                iAttempt = 1;
                
                oHover = 0;
            }else{
                iAttempt = 0;
            }
        }
        
        //  Find the tab container and optionally the tab page object
        oCardCon = null;
        while(oHover && !oCardCon){
            if(oHover instanceof df.WebTabPage){
                oCard = oHover;
            }
            if(oHover instanceof df.WebTabContainer){
                oCardCon = oHover;
            }
            oHover = oHover._oParent;
        }
        
        if(oCardCon){
            if(eTabBtn){    //  When hovering a tab button we will insert the tab before the tab that owns the button
                eInsertElem = eTabBtn;
                bBefore = true;
                
                //  Find the tab to which the button belongs
                for(i = 0; i < oCardCon._aCards.length; i++){
                    if(oCardCon._aCards[i]._eBtn === eTabBtn){
                        oNextCard = oCardCon._aCards[i];
                        break;
                    }
                }
            }else if(oCard){    //  When hovering the current tab itself we will insert the tab after the current tab
                eInsertElem = oCard._eBtn;
                bBefore = false;
                
                i = oCardCon._aCards.indexOf(oCard) + 1;
                oNextCard = oCardCon._aCards[i] || null;
            }else{  //  When hovering just the tab container we will insert at the end
                oNextCard = null;
                bBefore = false;
                
                //  Show after the last tab button
                for(i = oCardCon._aCards.length - 1; i >= 0; i--){
                    if(oCardCon._aCards[i].pbRender && oCardCon._aCards[i].pbVisible){  // TODO: Check if we pbVisible renders the tab button or not
                        eInsertElem = oCardCon._aCards[i]._eBtn;
                        break;
                    }
                }
                
                //  If no tab buttons available we show the marker at the beginning of the header bar
                if(!eInsertElem){
                    eInsertElem = oCardCon._eHead;
                    bBefore = true;
                }
            }
            
            oRect = df.sys.gui.getBoundRect(eInsertElem);
                        
            //  Reposition marker
            eMarker.style.top = oRect.top + "px";
            eMarker.style.left = (bBefore ? oRect.left : oRect.right) + "px";
            eMarker.style.height = oRect.height + "px";
            
            eMarker.style.display = "";
        }else{
            //  If we are not hovering a CardCon we hide the insertion marker and clear the settings
            hide.call(this);
        }
    }
    
    function drop(sJsClassName){
        var sProps = "";
        
        if(oCardCon){
            if(bCreate){
                sProps = 'psCaption:"Tabpage ' + (oCardCon._aCards.length + 1) + '"';
                this.oPrev.studioDropObject(sJsClassName, oCardCon, oNextCard, sProps);
            }else{
                //  If the newline changed for the newly inserted column we do that
                if(oStartCardCon !== oCardCon || oStartNextCard !== oNextCard){
                    this.oPrev.studioMoveObject(oObj, oCardCon, oNextCard, "");
                }
            }
        }
    }
    
    function end(){
        if(eMarker && eMarker.parentNode){
            eMarker.parentNode.removeChild(eMarker);
        }
        
        df.dom.removeClass(document.body, "dragcursor");
    }
    
    return {
        move : move,
        drop : drop,
        end : end,
        hide : hide
    };
}


}


df.WebTabPage.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesTabPageEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());