import { DesControlEditor } from './WebAppDesignerControlEditor.js';


df.generateCardButtons = function(oCC){
    var aHtml = [];
    
    aHtml.push('<div class="prev_cc_btns" data-dfcontainer="', oCC.getLongName(), '">');
    
    aHtml.push(df.generateCardButtonsContent(oCC, aHtml));
    
    aHtml.push('</div>');
    
    return df.dom.create(aHtml.join(''));
};

df.generateCardButtonsContent = function(oCC){
    var aHtml = [], i;
    
    for(i = 0; i < oCC._aCards.length; i++){
        aHtml.push('<span class="prev_cc_btn', (oCC._oCurrent === oCC._aCards[i] ? ' prev_cc_current' : ''), '" data-dfcard="', oCC._aCards[i]._sName, '">&nbsp;</span>');
    }
    
    return aHtml.join('');
};

export class DesCardContainerEditor extends DesControlEditor{

render(oObj){
    super.render(oObj);
    
    this.eButtons = df.generateCardButtons(this.oObj);
    this.eSel.appendChild(this.eButtons);
    
    df.dom.on("click", this.eButtons, this.onButtonClick, this);
}

select(oObj){
    super.select(oObj);
    
    this.eButtons.innerHTML = df.generateCardButtonsContent(oObj);
}
    

position(oRect){
    super.position(...arguments);
    
    this.eButtons.style.top = (oRect.top) + "px";
    this.eButtons.style.left = (oRect.left + oRect.width - this.eButtons.offsetWidth) + "px";
}


onButtonClick(oEvent){
    var sName, eCur, eBtn = oEvent.getTarget();
    
    if(eBtn.hasAttribute("data-dfcard")){
        sName = eBtn.getAttribute("data-dfcard");
        
        if(this.oObj[sName]){
            this.oObj[sName].show();
        }
        
        this.eButtons.innerHTML = df.generateCardButtonsContent(this.oObj);
        
    }
}



}


df.WebCardContainer.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev, bOptIgnoreSelect = false){    
        if(!oEditor){
            oEditor = new DesCardContainerEditor(oPrev);
        }
        
        if(this._bIsWO && !bOptIgnoreSelect){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());
df.WebAccordionContainer.prototype.getEditor = df.WebTabContainer.prototype.getEditor = (function(){
    var oEditor = null;
    
    return function(oPrev){    
        if(!oEditor){
            oEditor = new DesControlEditor(oPrev);
        }
        
        if(this._bIsWO){    //  Check if this is an initialized web object
            oEditor.select(this);
        }
        
        return oEditor;
    };
}());