/*
WebList designer subclass that makes it use the right designer controller (WebListDesignerController) 
and creates a preview row.
*/
export class WebList_Designer extends df.WebList{

constructor(sName, oPrnt){
    super(sName, oPrnt);
        
    this._bInitialized = false;
}

createController(){
    return new WebListDesignerController(this, this._oModel);
}

/*
Creates the header view module. Can be augmented for customization.
*/
createHeaderView(){
    return new WebListHeaderView_Designer(this, this._oModel, this._oController);
}

/*
Don't load a Layout cache.
*/
loadLayout(bLoadIntoMapper, bRedraw) {
    return null;
}

/*
This function recreates the column mapper and should redraw afterwards to take effect.
It also reorders the piPositions of all columns.
*/
rebuildColumnMapper(bRedraw) {
    if (typeof bRedraw != "boolean") bRedraw = true;
    
    this._aColumnMapper = this._aColumns;
    if (bRedraw) this.redraw();
}

//  Create a preview row that displays the captions as values
createPreviewRow(){
    const webListData = {
        aRows : [],
        aGroupHeaders : [],
        aGroups : []
    };
        
    for(let x = 0; x < 1; x++){
        webListData.aRows.push({
            sRowId : "preview_" + x,
            sCssClassName : "",
            aCells : this._aColumns.flatMap(oCol => {
                return {
                    sValue : oCol.psCaption,
                    sTooltip : "",
                    aOptions : []
                }
            }),
            iGroupHeaderIndex : -1
        });
    }

    this._oController.handleData(webListData, "page", "", true, true);
}

//  Augment create to insert preview row
create(){
    
    
    super.create();
    
    //  Insert preview row
    this.createPreviewRow();

    this._oModel.bLast = true;
    this._oModel.bFirst = true;
}

//  Augment redraw to update preview row (to reflect psCaption change)
redraw(){
    if(!this.pbShowHeader || !this.pbScroll){
       this.createPreviewRow();
    }
    
    super.redraw();
}

//  Kill focus logic

focus(oEvent){ }
onListClick(oEvent){ }
onFocus(oEvent){ }
onBlur(oEvent){ }

}

df.WebList.prototype.getDesignerClass = function(sType){
    return WebList_Designer;
};

