/*
Subclass WebListRowModel to augment HTML generation for the row.
*/
export class WebHtmlListRowModel_Designer extends df.WebHtmlListRowModel{
constructor(oList, oModel){
    super(oList, oModel);

    this.rRegEx = /{{([a-zA-Z0-9_\-]*)}}/g;
}
/*
Called to generate the HTML for a single row. Uses the regex to search for markers and replaces 
them with column values calling cellHtml on the columns.

@param  tRow    Struct with row data.
@param  aHtml   Array string builder for output.
@param  bZebra  True of odd rows, false for even.
*/
rowHtml(tRow, aHtml, bZebra){
    var oL = this.oL, oR = this.oR, that = this;
    
    aHtml.push(oL._sHtmlTemplate.replace(this.rRegEx, function(sMatch, sP1){
        if(sP1 == "dfrowid"){
            return tRow.sRowId;
        }
        var oCol = oL._oColMap[sP1];
        if(oCol){
            return '<span data-dfcolindex=' + oCol._iColIndex + '>' + that.cellHtml(oCol, tRow, tRow.aCells[oCol._iColIndex]) + '</span>';
        }
        return sMatch;
    }));
}

}


/*
Subclass WebListView to add psHtmlBefore, psHtmlAfter and OnElemClick logic.
*/
class WebHtmlListView_Designer extends WebHtmlListView{


/* 
Override for designer to make it catch up data-dfcolindex.

@param  oEvent  Event object.
@private
*/
onTableClick(oEv){
    var eElem = oEv.getTarget(), eRow = null, iCol = -1, that = this, sRowId = null, sElemClick = null, bRowClick = true;
    
    //  Check enabled state
    if(!this.oL.isEnabled() || this.bCancelClick){
        return;
    }
    
    //  We need to determine if and which row was clicked so we start at the clicked element and move up untill we find the row
    while(eElem.parentNode && eElem !== this.eBody && !sRowId){
        //  Check if we found the tr element and if it is part of the table
        if(eElem.hasAttribute("data-dfisrow")){  
            sRowId = eElem.getAttribute("data-dfrowid");
        }

        if(eElem.hasAttribute("data-dfcolindex")){
            iCol = eElem.getAttribute("data-dfcolindex");
        }
        eElem = eElem.parentNode;
    }

    //  Trigger regular cell click
    if(bRowClick && sRowId){
        //  Trigger cell click
        if(this.oC.cellClick(oEv, sRowId, iCol)){
            this._bPreventSubmit = true;
            setTimeout(function(){
                that.bPreventSubmit = false;
            }, 250);
            oEv.stop();    
        }
    }
}
}


/*
Designer class for the WebHtmlList that makes it use the WebListDesignerController (which seems 
to work just fine). Difference with the WebList_Designer is that it inherits from WebHtmlList 
which makes it show the actual HTML. Columns can still be dropped on it but can't be selected.
*/
class WebHtmlList_Designer extends df.WebHtmlList{
constructor(sName, oPrnt){
    super(sName, oPrnt);

    this._bInitialized = false;
}

createController(){
    return new WebListDesignerController(this, this._oModel);
}

//  Create a preview row that displays the captions as values
createPreviewRow(){
    const webListData = {
        aRows : [],
        aGroupHeaders : [],
        aGroups : []
    };
        
    for(let x = 0; x < 1; x++){
        webListData.aRows.push({
            sRowId : "preview_" + x,
            sCssClassName : "",
            aCells : this._aColumns.flatMap(oCol => {
                return {
                    sValue : oCol.psCaption,
                    sTooltip : "",
                    aOptions : []
                }
            }),
            iGroupHeaderIndex : -1
        });
    }

    this._oController.handleData(webListData, "page", "", true, true);
}

//  Augment create to insert preview row
create(){
    this.pbShowHeader = false;
    
    super.create();
    
    //  Insert preview row
    this.createPreviewRow();

    this._oModel.bLast = true;
    this._oModel.bFirst = true;
}


createRowModel(){
    return new WebHtmlListRowModel_Designer(this, this._oModel);
}

createView(){
    return new WebHtmlListView_Designer(this, this._oModel, this._oController);
}

//  Augment redraw to update preview row (to reflect psCaption change)
redraw(){
    if(!this.pbShowHeader || !this.pbScroll){
       this.createPreviewRow();
    }
    
    super.redraw();
}

//  Kill focus logic
focus(oEvent){ }
onListClick(oEvent){ }
onFocus(oEvent){ }
onBlur(oEvent){ }

getCell(iRow, iCol)
{
    return df.dom.query(this._eElem, 'span[data-dfcolindex="' + iCol + '"]', false);
}


}

df.WebHtmlList.prototype.getDesignerClass = function(sType){
    return WebHtmlList_Designer;
};