updateCSS(bResize){
    super.updateCSS(bResize);
    
    //  Update theme path if needed
    if(this._eStyleApplication){
        if(this._eStyleApplication.href.indexOf(this._sRootPath + "CssStyle/application.css") < 0){
            this._eStyleApplication.href = this._sRootPath + "CssStyle/application.css";
        }
    }
}

/* - - - - - - Persistent Props - - - - - - - */

storeProp(oObj, sProp, sVal){
    // TODO: Make this work with object id instead of name?
    var i, oObjProps = null, sObjName = oObj.getLongName();
    
    //  Find obj
    for(i = 0; i < this._aObjProps.length; i++){
        if(this._aObjProps[i].sN === sObjName){
            oObjProps = this._aObjProps[i];
            break;
        }
    }    
    
    //  Creat if not found
    if(!oObjProps){
        oObjProps = { sN : sObjName, aP : [] };
        this._aObjProps.push(oObjProps);
    }
    
    //  Find property
    for(i = 0; i < oObjProps.aP.length; i++){
        if(oObjProps.aP[i].sN === sProp){
            oObjProps.aP[i].sV = sVal;
            return;
        }
    }
    
    //  Add property
    oObjProps.aP.push({ sN : sProp, sV : sVal });
}

getProp(oObj, sProp){
    var i, oObjProps = null, sObjName = oObj.getLongName();
    
    //  Find obj
    for(i = 0; i < this._aObjProps.length; i++){
        if(this._aObjProps[i].sN === sObjName){
            oObjProps = this._aObjProps[i];
            break;
        }
    }    
    
    //  Find property
    if(oObjProps){
        for(i = 0; i < oObjProps.aP.length; i++){
            if(oObjProps.aP[i].sN === sProp){
                return oObjProps.aP[i].sV;
            }
        }
    }
    
    return null;
}

