import { DesUIObjectEditor } from './WebAppDesignerUIObjectEditor.js';
import { DesGridMixin } from './WebAppDesignerGridMixin.js';

class DesContainerEditorBase extends DesGridMixin(DesUIObjectEditor) { }

export class DesContainerEditor extends DesContainerEditorBase {

    constructor(oPrev) {
        super(oPrev);
    }

select(oObj) {
    super.select(...arguments)

    this._oContainer = oObj;

    if (!this.eSel) {
        this.render(oObj);
    }

    if (oObj.isGridLayout()) {
        this.destroyGrid();
        this.drawGridOverLay(oObj);
        
        if(!this._bGridVisible) {
            this.hideGrid();
        }

        if (this._eGridOverLay) {
            this.addGridHandlers();
        }
        if (this._eToggleGridBtn) {
            this._eToggleGridBtn.style.display = "";
        }
    }

    this.reposition();
}

unselect(oNewSel) {
    super.unselect(...arguments)

    if (this.eSel) {
        this.eSel.style.display = "none";

        if (this.eRuler && this.eRuler.parentNode) {
            this.eRuler.parentNode.removeChild(this.eRuler);
        }

        this.destroyGrid();
        // if (this._eGridOverLay) {
        //   this._eGridOverLay.style.display = "none";
        //   this._eGridOverLay.style.zIndex = -1;
        // }
        if (this._eToggleGridBtn) {
            this._eToggleGridBtn.style.display = "none";
        }
    }

    // this.oPrev.hideContainerMenu();
}

render(oObj) {
    var eSel;

    this.eSel = eSel = df.dom.create('<div class="preview_selected ' + this.sSelectorClassName + '" style="display: none"><div class="prev_s_top"><div class="prev_incr_col"></div><div class="prev_decr_col"></div></div><div class="prev_s_right"></div><div class="prev_s_left"></div><div class="prev_s_bottom"></div></div>');

    this.eSelTop = df.dom.query(eSel, 'div.prev_s_top');
    this.eSelLeft = df.dom.query(eSel, 'div.prev_s_left');
    this.eSelBottom = df.dom.query(eSel, 'div.prev_s_bottom');
    this.eSelRight = df.dom.query(eSel, 'div.prev_s_right');
    this.eIncrCol = df.dom.query(eSel, 'div.prev_incr_col');
    this.eDecrCol = df.dom.query(eSel, 'div.prev_decr_col');

    df.events.addDomListener("mousedown", this.eIncrCol, this.onIncrement, this);
    df.events.addDomListener("mousedown", this.eDecrCol, this.onDecrement, this);

    this.oPrev._eRenderTo.parentNode.appendChild(eSel);
}

reposition() {
    var eElem;

    if (this.eSel && this.oObj) {
        eElem = this.getPreviewerElem();

        if (eElem && this.oObj._bShown && df.sys.gui.isOnScreen(eElem)) {
            this.position(df.sys.gui.getBoundRect(eElem));
        } else {
            this.eSel.style.display = "none";
        }
    }

    if (this._oContainer && this._oContainer.isGridLayout()) {
        this.positionGridOverlay();
    }

}

position(oRect) {
    //  Reposition / (re)create ruler
    if (!this.oObj._bPanels) {
        if (!this.eRuler || !this.eRuler.parentNode || this.iRulerColumns !== this.oObj.piColumnCount) {
            if (this.eRuler && this.eRuler.parentNode) {
                this.eRuler.parentNode.removeChild(this.eRuler);
            }

            this.iRulerColumns = this.oObj.piColumnCount;
            this.eRuler = this.oPrev.renderRuler(this.oObj);
            this.oPrev._eRenderTo.appendChild(this.eRuler);
        } else {
            this.oPrev.positionRuler(this.eRuler, this.oObj);
        }
    }

    this.eIncrCol.style.display = (this.oObj._bPanels || this._oContainer?.isGridLayout() ? 'none' : '');
    this.eDecrCol.style.display = (this.oObj._bPanels || this._oContainer?.isGridLayout() ? 'none' : '');

    // Position grid
    if (this._oContainer && this._oContainer.isGridLayout()) {
        this.positionGridOverlay();
    }

    super.position(oRect);
}

onIncrement(oEv) {
    var iCount = this.oObj.piColumnCount;

    if (iCount < 100) {
        iCount++;

        this.oObj.set("piColumnCount", iCount);
        this.oPrev.studioUpdateProp(this.oObj, "piColumnCount", iCount);
    }

    oEv.stop();
}

onDecrement(oEv) {
    var iCount = this.oObj.piColumnCount;

    if (iCount > 1) {
        iCount--;

        this.oObj.set("piColumnCount", iCount);
        this.oPrev.studioUpdateProp(this.oObj, "piColumnCount", iCount);
    }

    oEv.stop();
}

keypress(oEvent) {
    var oObj = this.oObj, iCount;

    super.keypress(...arguments)

    if (oObj) {
        iCount = oObj.piColumnCount;

        if (oEvent.matchKey(df.settings.designerKeys.decrementColCount)) {
            if (iCount > 1) {
                iCount--;

                this.oObj.set("piColumnCount", iCount);
                this.oPrev.studioUpdateProp(this.oObj, "piColumnCount", iCount);

                oEvent.stop();
            }
        }

        if (oEvent.matchKey(df.settings.designerKeys.incrementColCount)) {
            if (iCount < 99) {
                iCount++;

                this.oObj.set("piColumnCount", iCount);
                this.oPrev.studioUpdateProp(this.oObj, "piColumnCount", iCount);

                oEvent.stop();
            }
        }
    }
}

// Grid stuff
// Now in WebAppDesignerGridMixin

}


df.WebBaseContainer.prototype.getEditor = (function () {
    var oEditor = null;

    return function (oPrev, bOptIgnoreSelect = false) {
        if (!oEditor) {
            oEditor = new DesContainerEditor(oPrev);
        }
        
        if (this._bIsWO && !bOptIgnoreSelect) {    //  Check if this is an initialized web object
            oEditor.select(this);
        }

        return oEditor;
    };
}());